{
  "name": "Solar Biker: Jhonny's PR Adventure",
  "description": "An action-packed endless runner where Jhonny the T-Rex rides his motorcycle through Puerto Rico, dodging solar panels and collecting suns."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAMEOVER = 'GAMEOVER'
}

export interface GameObject {
  x: number;
  y: number;
  width: number;
  height: number;
}

export interface Obstacle extends GameObject {
  type: 'solar_panel';
}

export interface Collectible extends GameObject {
  type: 'sun';
}

export const CITIES = [
  "San Juan",
  "Bayamón",
  "Ponce",
  "Mayagüez",
  "Caguas",
  "Arecibo",
  "Carolina"
];

export const PR_PHRASES = [
  "¡Vamo' arriba, dale!",
  "¡Qué mangó, sigue intentando!",
  "¡No te quites, boricua!",
  "¡Ay bendito, otra vez!",
  "¡Eche, dale suave!",
  "¡Mano, te fuiste en güira!",
  "¡Chequea eso, dale de nuevo!"
];

export const GRAVITY = 0.6;
export const JUMP_FORCE = -15;
export const BASE_SPEED = 6;
export const SPEED_INCREMENT = 1.5;
export const METERS_PER_CITY = 5000;
export const SUNS_FOR_POWERUP = 5;
export const POWERUP_BOOST_DISTANCE = 300;
export const TREX_IMAGE_URL = 'https://i.postimg.cc/mtMKfpYG/trex-jhonny.png';
export const LOGO_IMAGE_URL = 'https://i.postimg.cc/6T5J2v2G/logo.png';

import React, { useState, useCallback } from 'react';
import { GameState, CITIES, PR_PHRASES } from './types';
import Game from './components/Game';
import Menu from './components/Menu';
import GameOver from './components/GameOver';
import { LOGO_IMAGE_URL } from './constants';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [distance, setDistance] = useState(0);
  const [finalCity, setFinalCity] = useState(CITIES[0]);

  const startGame = () => {
    setGameState(GameState.PLAYING);
    setScore(0);
    setDistance(0);
  };

  const endGame = (finalScore: number, finalDist: number, city: string) => {
    setScore(finalScore);
    setDistance(Math.floor(finalDist));
    setFinalCity(city);
    setGameState(GameState.GAMEOVER);
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-sky-300 select-none">
      {/* Company Logo Header */}
      <div className="absolute top-4 left-4 z-50 flex items-center gap-2">
        <img 
          src={LOGO_IMAGE_URL} 
          alt="Company Logo" 
          className="h-16 w-auto drop-shadow-lg"
          onError={(e) => {
            // Fallback for broken image link
            (e.target as HTMLImageElement).src = "https://picsum.photos/100/100?grayscale";
          }}
        />
        <h1 className="text-4xl font-cartoon text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] hidden sm:block">
          SOLAR BIKER
        </h1>
      </div>

      {gameState === GameState.MENU && <Menu onStart={startGame} />}

      {gameState === GameState.PLAYING && (
        <Game onGameOver={endGame} />
      )}

      {gameState === GameState.GAMEOVER && (
        <GameOver 
          score={score} 
          distance={distance} 
          city={finalCity} 
          onRestart={startGame} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE 
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string) => void;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  // Game state refs (to avoid stale closures in loop)
  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);

  // Player state
  const player = useRef({
    x: 100,
    y: 0,
    width: 120,
    height: 120,
    dy: 0,
    isJumping: false,
    boostRemaining: 0,
    guayandoTimer: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const backgrounds = useRef<{x: number, speed: number, color: string}[]>([]);

  const trexImg = useRef<HTMLImageElement>(new Image());

  // Initialization
  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;

    // Initialize Parallax Background layers
    backgrounds.current = [
      { x: 0, speed: 0.2, color: '#fbbf24' }, // Far back
      { x: 0, speed: 0.5, color: '#10b981' }, // Middle
      { x: 0, speed: 1.0, color: '#3b82f6' }  // Near
    ];

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space' && !player.current.isJumping) {
        player.current.dy = JUMP_FORCE;
        player.current.isJumping = true;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const spawnObstacle = (canvasWidth: number, canvasHeight: number) => {
    if (Math.random() < 0.02) {
      obstacles.current.push({
        x: canvasWidth,
        y: canvasHeight - 110,
        width: 60,
        height: 80,
        type: 'solar_panel'
      });
    }
  };

  const spawnCollectible = (canvasWidth: number, canvasHeight: number) => {
    if (Math.random() < 0.015) {
      collectibles.current.push({
        x: canvasWidth,
        y: canvasHeight - 200 - Math.random() * 150,
        width: 40,
        height: 40,
        type: 'sun'
      });
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 50;

    // Progression & Speed
    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 10 : 0);

    // Increment distance
    distance.current += currentSpeed / 60; // Approximate m/frame

    // Check City Change
    const nextCityIndex = Math.min(Math.floor(distance.current / METERS_PER_CITY), CITIES.length - 1);
    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 60; // Show "GUAYANDO" on city change too
    }

    // Player Physics
    player.current.y += player.current.dy;
    if (player.current.y + player.current.height < groundY) {
      player.current.dy += GRAVITY;
    } else {
      player.current.y = groundY - player.current.height;
      player.current.dy = 0;
      player.current.isJumping = false;
    }

    // Boost Logic
    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
      if (player.current.boostRemaining <= 0) {
        player.current.boostRemaining = 0;
      }
    }

    if (player.current.guayandoTimer > 0) {
      player.current.guayandoTimer--;
    }

    // Spawning
    spawnObstacle(width, height);
    spawnCollectible(width, height);

    // Update Obstacles
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;

      // Collision
      if (
        player.current.x < obs.x + obs.width &&
        player.current.x + player.current.width - 20 > obs.x && // Tweak hitboxes
        player.current.y < obs.y + obs.height &&
        player.current.y + player.current.height > obs.y
      ) {
        if (player.current.boostRemaining <= 0) {
          gameActive.current = false;
          onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
        }
      }

      if (obs.x + obs.width < 0) {
        obstacles.current.splice(index, 1);
      }
    });

    // Update Collectibles
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;

      // Collision
      if (
        player.current.x < item.x + item.width &&
        player.current.x + player.current.width > item.x &&
        player.current.y < item.y + item.height &&
        player.current.y + player.current.height > item.y
      ) {
        collectibles.current.splice(index, 1);
        sunsCollected.current += 1;
        totalScore.current += 100;

        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 60; // ~1 second at 60fps
        }
      }

      if (item.x + item.width < 0) {
        collectibles.current.splice(index, 1);
      }
    });

    // Draw
    draw(ctx, width, height, groundY, currentSpeed);

    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number, currentSpeed: number) => {
    // Clear
    ctx.clearRect(0, 0, width, height);

    // Sky gradient
    const gradient = ctx.createLinearGradient(0, 0, 0, height);
    gradient.addColorStop(0, '#0ea5e9'); // Sky Blue
    gradient.addColorStop(1, '#7dd3fc'); // Light Blue
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, width, height);

    // Draw City Info
    ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
    ctx.font = '32px Bangers';
    ctx.textAlign = 'right';
    ctx.fillText(`CIUDAD: ${CITIES[currentCityIndex.current].toUpperCase()}`, width - 20, 50);
    ctx.fillText(`DISTANCIA: ${Math.floor(distance.current)}m`, width - 20, 90);
    ctx.fillText(`SOLES: ${sunsCollected.current}`, width - 20, 130);

    // Road
    ctx.fillStyle = '#4b5563';
    ctx.fillRect(0, groundY, width, 50);
    ctx.strokeStyle = 'white';
    ctx.setLineDash([40, 40]);
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(0, groundY + 25);
    ctx.lineTo(width, groundY + 25);
    ctx.stroke();
    ctx.setLineDash([]);

    // Obstacles
    obstacles.current.forEach(obs => {
      // Solar Panel drawing
      ctx.fillStyle = '#1e3a8a';
      ctx.fillRect(obs.x, obs.y, obs.width, obs.height);
      ctx.strokeStyle = '#60a5fa';
      ctx.lineWidth = 2;
      ctx.strokeRect(obs.x + 5, obs.y + 5, obs.width - 10, obs.height - 10);
      // Grid lines
      ctx.beginPath();
      ctx.moveTo(obs.x + obs.width/2, obs.y);
      ctx.lineTo(obs.x + obs.width/2, obs.y + obs.height);
      ctx.moveTo(obs.x, obs.y + obs.height/2);
      ctx.lineTo(obs.x + obs.width, obs.y + obs.height/2);
      ctx.stroke();
    });

    // Collectibles
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fbbf24';
      ctx.beginPath();
      ctx.arc(sun.x + sun.width/2, sun.y + sun.height/2, sun.width/2, 0, Math.PI * 2);
      ctx.fill();
      // Rays
      ctx.strokeStyle = '#f59e0b';
      for(let i=0; i<8; i++) {
        const angle = (i / 8) * Math.PI * 2;
        ctx.beginPath();
        ctx.moveTo(sun.x + sun.width/2, sun.y + sun.height/2);
        ctx.lineTo(
          sun.x + sun.width/2 + Math.cos(angle) * (sun.width/2 + 10),
          sun.y + sun.height/2 + Math.sin(angle) * (sun.width/2 + 10)
        );
        ctx.stroke();
      }
    });

    // Player (T-Rex)
    if (trexImg.current.complete) {
      ctx.save();
      if (player.current.boostRemaining > 0) {
        ctx.shadowBlur = 20;
        ctx.shadowColor = 'yellow';
      }
      ctx.drawImage(
        trexImg.current, 
        player.current.x, 
        player.current.y, 
        player.current.width, 
        player.current.height
      );
      ctx.restore();
    } else {
      ctx.fillStyle = 'green';
      ctx.fillRect(player.current.x, player.current.y, player.current.width, player.current.height);
    }

    // "GUAYANDO!!" Text
    if (player.current.guayandoTimer > 0) {
      ctx.fillStyle = 'white';
      ctx.strokeStyle = 'red';
      ctx.lineWidth = 4;
      ctx.font = 'italic 70px Permanent Marker';
      ctx.textAlign = 'center';
      const shakeX = (Math.random() - 0.5) * 10;
      const shakeY = (Math.random() - 0.5) * 10;
      ctx.strokeText("GUAYANDO!!", width/2 + shakeX, height/2 + shakeY);
      ctx.fillText("GUAYANDO!!", width/2 + shakeX, height/2 + shakeY);
    }
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(update);
    return () => window.removeEventListener('resize', handleResize);
  }, [update]);

  return (
    <canvas 
      ref={canvasRef} 
      className="w-full h-full cursor-pointer" 
      onClick={() => {
        if (!player.current.isJumping) {
          player.current.dy = JUMP_FORCE;
          player.current.isJumping = true;
        }
      }}
    />
  );
};

export default Game;

import React, { useMemo } from 'react';
import { PR_PHRASES } from '../types';

interface GameOverProps {
  score: number;
  distance: number;
  city: string;
  onRestart: () => void;
}

const GameOver: React.FC<GameOverProps> = ({ score, distance, city, onRestart }) => {
  const randomPhrase = useMemo(() => 
    PR_PHRASES[Math.floor(Math.random() * PR_PHRASES.length)], 
  []);

  return (
    <div className="absolute inset-0 z-40 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-500">
      <div className="bg-white rounded-3xl p-10 max-w-md w-full border-8 border-red-500 shadow-2xl transform rotate-2">
        <div className="text-center mb-8">
          <h2 className="text-7xl font-cartoon text-red-600 mb-4 drop-shadow-lg">¡QUEDASTE!</h2>
          <p className="text-2xl font-graffiti text-gray-800 animate-bounce">
            {randomPhrase}
          </p>
        </div>

        <div className="space-y-6 mb-10">
          <div className="flex justify-between items-center border-b-4 border-dashed border-gray-200 pb-2">
            <span className="text-xl font-cartoon text-gray-500 uppercase">Distancia:</span>
            <span className="text-3xl font-cartoon text-blue-600">{distance}m</span>
          </div>
          <div className="flex justify-between items-center border-b-4 border-dashed border-gray-200 pb-2">
            <span className="text-xl font-cartoon text-gray-500 uppercase">Soles:</span>
            <span className="text-3xl font-cartoon text-yellow-600">{score / 100}</span>
          </div>
          <div className="flex justify-between items-center border-b-4 border-dashed border-gray-200 pb-2">
            <span className="text-xl font-cartoon text-gray-500 uppercase">Última Ciudad:</span>
            <span className="text-2xl font-cartoon text-emerald-600">{city}</span>
          </div>
        </div>

        <div className="grid grid-cols-1 gap-4">
          <button 
            onClick={onRestart}
            className="w-full py-5 bg-emerald-500 hover:bg-emerald-600 text-white font-cartoon text-4xl rounded-2xl shadow-lg transform transition active:scale-95 border-b-8 border-emerald-800"
          >
            OTRA VUELTA
          </button>

          <button 
            onClick={() => window.location.reload()}
            className="w-full py-3 text-gray-500 font-cartoon text-xl hover:text-gray-700 underline"
          >
            Volver al Menú
          </button>
        </div>
      </div>
    </div>
  );
};

export default GameOver;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE 
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string) => void;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  size: number;
  color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);

  const player = useRef({
    x: 120,
    y: 0,
    width: 130,
    height: 130,
    dy: 0,
    rotation: 0,
    isJumping: false,
    boostRemaining: 0,
    guayandoTimer: 0,
    vibration: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const clouds = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;

    // Generar nubes iniciales
    for(let i=0; i<5; i++) {
      clouds.current.push({
        x: Math.random() * window.innerWidth,
        y: 50 + Math.random() * 150,
        size: 50 + Math.random() * 80,
        speed: 0.5 + Math.random() * 1
      });
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.code === 'Space' || e.code === 'ArrowUp') && !player.current.isJumping) {
        player.current.dy = JUMP_FORCE;
        player.current.isJumping = true;
        // Partículas al saltar
        createExplosion(player.current.x + 40, player.current.y + 110, '#cbd5e1');
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<8; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 5,
        vy: (Math.random() - 0.5) * 5,
        life: 1.0,
        size: 4 + Math.random() * 6,
        color
      });
    }
  };

  const spawnObstacle = (canvasWidth: number, canvasHeight: number) => {
    if (Math.random() < 0.015) {
      obstacles.current.push({
        x: canvasWidth,
        y: canvasHeight - 140, // Un poco más arriba para la base
        width: 70,
        height: 90,
        type: 'solar_panel',
        glow: 0
      });
    }
  };

  const spawnCollectible = (canvasWidth: number, canvasHeight: number) => {
    if (Math.random() < 0.012) {
      collectibles.current.push({
        x: canvasWidth,
        y: canvasHeight - 220 - Math.random() * 120,
        width: 45,
        height: 45,
        type: 'sun'
      });
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundHeight = 80;
    const groundY = height - groundHeight;

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 12 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.min(Math.floor(distance.current / METERS_PER_CITY), CITIES.length - 1);
    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 80;
    }

    // Física y Animación de Jhonny
    player.current.y += player.current.dy;
    if (player.current.y + player.current.height < groundY) {
      player.current.dy += GRAVITY;
      // Inclinación según velocidad vertical
      player.current.rotation = player.current.dy * 0.025;
    } else {
      if (player.current.isJumping) { // Aterrizaje
         createExplosion(player.current.x + 60, groundY, '#94a3b8');
      }
      player.current.y = groundY - player.current.height;
      player.current.dy = 0;
      player.current.isJumping = false;
      player.current.rotation = Math.sin(Date.now() / 100) * 0.02; // Vibración del motor
    }

    // Efecto Boost (Fuego/Humo)
    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
      // Partículas de nitro
      if (Math.random() > 0.5) {
        particles.current.push({
          x: player.current.x + 10,
          y: player.current.y + 100,
          vx: -5 - Math.random() * 5,
          vy: (Math.random() - 0.5) * 2,
          life: 0.8,
          size: 5 + Math.random() * 10,
          color: Math.random() > 0.5 ? '#f59e0b' : '#ef4444'
        });
      }
      if (player.current.boostRemaining <= 0) player.current.boostRemaining = 0;
    }

    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;

    // Actualizar Nubes
    clouds.current.forEach(cloud => {
      cloud.x -= cloud.speed;
      if (cloud.x + cloud.size < 0) cloud.x = width + cloud.size;
    });

    // Actualizar Partículas
    particles.current.forEach((p, i) => {
      p.x += p.vx;
      p.y += p.vy;
      p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    spawnObstacle(width, height);
    spawnCollectible(width, height);

    // Obstáculos
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      obs.glow = Math.sin(Date.now() / 200) * 10;

      // Collision (Hitbox ajustada)
      const hitPadding = 30;
      if (
        player.current.x + hitPadding < obs.x + obs.width &&
        player.current.x + player.current.width - hitPadding > obs.x &&
        player.current.y + hitPadding < obs.y + obs.height &&
        player.current.y + player.current.height - 10 > obs.y
      ) {
        if (player.current.boostRemaining <= 0) {
          gameActive.current = false;
          onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
        } else {
          // Si tiene boost, destruye el obstáculo!
          createExplosion(obs.x + obs.width/2, obs.y + obs.height/2, '#3b82f6');
          obstacles.current.splice(index, 1);
          totalScore.current += 500;
        }
      }
      if (obs.x + obs.width < -100) obstacles.current.splice(index, 1);
    });

    // Colectables
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (
        player.current.x < item.x + item.width &&
        player.current.x + player.current.width > item.x &&
        player.current.y < item.y + item.height &&
        player.current.y + player.current.height > item.y
      ) {
        collectibles.current.splice(index, 1);
        sunsCollected.current += 1;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 80;
        }
      }
      if (item.x + item.width < 0) collectibles.current.splice(index, 1);
    });

    draw(ctx, width, height, groundY, currentSpeed);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number, currentSpeed: number) => {
    ctx.clearRect(0, 0, width, height);

    // 1. Cielo y Montañas (Fondo)
    const skyGrad = ctx.createLinearGradient(0, 0, 0, height);
    skyGrad.addColorStop(0, '#0284c7');
    skyGrad.addColorStop(0.6, '#bae6fd');
    ctx.fillStyle = skyGrad;
    ctx.fillRect(0, 0, width, height);

    // Montañas lejanas
    ctx.fillStyle = '#059669';
    ctx.beginPath();
    ctx.moveTo(0, groundY);
    ctx.quadraticCurveTo(width * 0.25, groundY - 150, width * 0.5, groundY);
    ctx.quadraticCurveTo(width * 0.75, groundY - 200, width, groundY);
    ctx.fill();

    // Nubes
    ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
    clouds.current.forEach(c => {
      ctx.beginPath();
      ctx.arc(c.x, c.y, c.size * 0.4, 0, Math.PI * 2);
      ctx.arc(c.x + c.size * 0.3, c.y - c.size * 0.1, c.size * 0.35, 0, Math.PI * 2);
      ctx.arc(c.x + c.size * 0.5, c.y + c.size * 0.05, c.size * 0.3, 0, Math.PI * 2);
      ctx.fill();
    });

    // 2. Carretera
    // Césped/Tierra lateral
    ctx.fillStyle = '#15803d';
    ctx.fillRect(0, groundY, width, height - groundY);

    // Asfalto
    const roadWidth = height - groundY - 20;
    ctx.fillStyle = '#334155';
    ctx.fillRect(0, groundY + 10, width, roadWidth);

    // Líneas de la carretera (Animadas)
    ctx.strokeStyle = '#fde047';
    ctx.lineWidth = 6;
    ctx.setLineDash([60, 60]);
    ctx.lineDashOffset = (distance.current * 10) % 120;
    ctx.beginPath();
    ctx.moveTo(0, groundY + 10 + roadWidth/2);
    ctx.lineTo(width, groundY + 10 + roadWidth/2);
    ctx.stroke();
    ctx.setLineDash([]);

    // Bordes de cemento
    ctx.fillStyle = '#94a3b8';
    ctx.fillRect(0, groundY + 8, width, 4);
    ctx.fillRect(0, groundY + 10 + roadWidth - 4, width, 4);

    // 3. Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // 4. Obstáculos (Paneles Solares Pro)
    obstacles.current.forEach(obs => {
      // Poste
      ctx.fillStyle = '#64748b';
      ctx.fillRect(obs.x + obs.width/2 - 5, obs.y + obs.height - 20, 10, 60);

      // Panel
      ctx.save();
      ctx.shadowBlur = obs.glow;
      ctx.shadowColor = '#60a5fa';
      ctx.fillStyle = '#1e3a8a';
      ctx.strokeStyle = '#93c5fd';
      ctx.lineWidth = 3;
      // Dibujar con perspectiva leve
      ctx.beginPath();
      ctx.moveTo(obs.x, obs.y + 10);
      ctx.lineTo(obs.x + obs.width, obs.y);
      ctx.lineTo(obs.x + obs.width, obs.y + obs.height - 20);
      ctx.lineTo(obs.x, obs.y + obs.height - 10);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();

      // Rejilla interna
      ctx.lineWidth = 1;
      ctx.beginPath();
      for(let i=1; i<4; i++) {
        ctx.moveTo(obs.x + (obs.width/4)*i, obs.y + 5);
        ctx.lineTo(obs.x + (obs.width/4)*i, obs.y + obs.height - 15);
        ctx.moveTo(obs.x, obs.y + (obs.height/4)*i);
        ctx.lineTo(obs.x + obs.width, obs.y + (obs.height/4)*i - 5);
      }
      ctx.stroke();
      ctx.restore();
    });

    // 5. Colectables (Soles con brillo)
    collectibles.current.forEach(sun => {
      ctx.save();
      ctx.shadowBlur = 15;
      ctx.shadowColor = 'yellow';
      ctx.fillStyle = '#fbbf24';
      ctx.beginPath();
      ctx.arc(sun.x + sun.width/2, sun.y + sun.height/2, sun.width/2, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    });

    // 6. Player (Jhonny con rotación y efectos)
    if (trexImg.current.complete) {
      ctx.save();
      ctx.translate(player.current.x + player.current.width / 2, player.current.y + player.current.height / 2);
      ctx.rotate(player.current.rotation);

      if (player.current.boostRemaining > 0) {
        ctx.shadowBlur = 30;
        ctx.shadowColor = '#facc15';
      }

      ctx.drawImage(
        trexImg.current, 
        -player.current.width / 2, 
        -player.current.height / 2, 
        player.current.width, 
        player.current.height
      );
      ctx.restore();
    }

    // 7. UI Superior
    ctx.fillStyle = 'white';
    ctx.strokeStyle = 'black';
    ctx.lineWidth = 4;
    ctx.font = '40px Bangers';
    ctx.textAlign = 'right';
    const uiText = `${CITIES[currentCityIndex.current].toUpperCase()} | ${Math.floor(distance.current)}m | SOLES: ${sunsCollected.current}`;
    ctx.strokeText(uiText, width - 20, 50);
    ctx.fillText(uiText, width - 20, 50);

    // Barra de Boost
    if (player.current.boostRemaining > 0) {
      const barW = 200;
      const progress = player.current.boostRemaining / POWERUP_BOOST_DISTANCE;
      ctx.fillStyle = 'rgba(0,0,0,0.5)';
      ctx.fillRect(width - 220, 70, barW, 20);
      ctx.fillStyle = '#f59e0b';
      ctx.fillRect(width - 220, 70, barW * progress, 20);
    }

    // "GUAYANDO!!" Text
    if (player.current.guayandoTimer > 0) {
      ctx.save();
      ctx.translate(width/2, height/2 - 100);
      ctx.scale(1 + Math.sin(Date.now()/50)*0.1, 1 + Math.sin(Date.now()/50)*0.1);
      ctx.fillStyle = '#ef4444';
      ctx.strokeStyle = 'white';
      ctx.lineWidth = 8;
      ctx.font = 'italic 90px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.strokeText("GUAYANDO!!", 0, 0);
      ctx.fillText("GUAYANDO!!", 0, 0);
      ctx.restore();
    }
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(update);
    return () => window.removeEventListener('resize', handleResize);
  }, [update]);

  return (
    <canvas 
      ref={canvasRef} 
      className="w-full h-full cursor-pointer" 
      onClick={() => {
        if (!player.current.isJumping) {
          player.current.dy = JUMP_FORCE;
          player.current.isJumping = true;
          createExplosion(player.current.x + 40, player.current.y + 110, '#cbd5e1');
        }
      }}
    />
  );
};

export default Game;

export const GRAVITY = 0.7; // Un poco más de gravedad para que caiga rápido
export const JUMP_FORCE = -17; // Salto más potente
export const BASE_SPEED = 7; 
export const SPEED_INCREMENT = 1.2;
export const METERS_PER_CITY = 4000; // Ciudades más cortas para ver más variedad
export const SUNS_FOR_POWERUP = 5;
export const POWERUP_BOOST_DISTANCE = 500; // Boost más largo
export const TREX_IMAGE_URL = 'https://i.postimg.cc/mtMKfpYG/trex-jhonny.png';
export const LOGO_IMAGE_URL = 'https://i.postimg.cc/6T5J2v2G/logo.png';

export const GRAVITY = 0.8;
export const JUMP_FORCE = -15;
export const DOUBLE_JUMP_FORCE = -13;
export const BASE_SPEED = 8; 
export const SPEED_INCREMENT = 1.0;
export const METERS_PER_CITY = 200; // Cambio rápido de nivel cada 200m
export const MAX_LIVES = 3;
export const SUNS_FOR_POWERUP = 5;
export const POWERUP_BOOST_DISTANCE = 400;

export const TREX_IMAGE_URL = 'https://i.postimg.cc/mtMKfpYG/trex-jhonny.png';
export const LOGO_IMAGE_URL = 'https://i.postimg.cc/6T5J2v2G/logo.png';

export const BACKGROUND_URLS = [
  "https://wallpaperaccess.com/full/1137576.jpg",
  "https://wallpapers.com/images/hd/puerto-rico-island-aerial-view-xatbur3hk5mja77d.jpg",
  "https://wallpapercave.com/wp/oJ4TXh3.jpg",
  "https://thumbs.dreamstime.com/b/rocky-coast-puerto-rico-14186251.jpg",
  "https://live.staticflickr.com/4384/37192967871_90b4ab467f_b.jpg",
  "https://jetsytravels.com/wp-content/uploads/2019/03/osj-6398.jpg",
  "https://th.bing.com/th/id/R.39bec973b88cf277c453325982ec646a?rik=6cu92l3FdoLrTw&riu=http%3a%2f%2fwallpapercave.com%2fwp%2fEvLKM3D.jpg&ehk=zvMS0Nrclin%2fNQqur66BMer5Q8krY53qS5KUUarJdEU%3d&risl=&pid=ImgRaw&r=0"
];

export const ERROR_PHRASES = [
  "¡Ya no quiero selvicio!",
  "¡Prefiero quedarme con LUMA!",
  "¡Quiero cancelar!",
  "¡Mano, la luz se fue!",
  "¡Esto no prende ni con fe!",
  "¡Ay bendito, otro apagón!"
];

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAMEOVER = 'GAMEOVER',
  WIN = 'WIN'
}

export interface GameObject {
  x: number;
  y: number;
  width: number;
  height: number;
}

export const CITIES = [
  "San Juan (Metro)",
  "Mayagüez (Oeste)",
  "Ponce (Sur)",
  "Arecibo (Norte)",
  "Fajardo (Este)",
  "Vieques (Isla)",
  "Culebra (Paraíso)"
];

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const lastErrorPhrase = useRef("");
  const invincibilityFrames = useRef(0);

  const player = useRef({
    x: 100,
    y: 0,
    width: 140,
    height: 140,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    vibration: 0,
    isJumping: false
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;

    // Pre-cargar fondos
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.code === 'Space' || e.code === 'ArrowUp')) {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          createExplosion(player.current.x + 30, player.current.y + 120, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<12; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 8,
        vy: (Math.random() - 0.5) * 8,
        life: 1.0,
        size: 2 + Math.random() * 5,
        color
      });
    }
  };

  const spawnObstacle = (canvasWidth: number, canvasHeight: number) => {
    if (Math.random() < 0.02) {
      obstacles.current.push({
        x: canvasWidth,
        y: canvasHeight - 160,
        width: 80,
        height: 110,
        type: 'solar_panel',
        tilt: (Math.random() - 0.5) * 0.4
      });
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 100;

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 15 : 0);
    distance.current += currentSpeed / 60;

    // Lógica de Ciudades / Victoria
    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);
    if (nextCityIndex >= BACKGROUND_URLS.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 100;
    }

    // Física
    player.current.y += player.current.dy;
    if (player.current.y + player.current.height < groundY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.03;
    } else {
      player.current.y = groundY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;
      player.current.isJumping = false;
      player.current.rotation = Math.sin(Date.now() / 80) * 0.03; // Vibración constante de la motora

      // Chispas constantes en suelo
      if (Math.random() > 0.7) {
        particles.current.push({
          x: player.current.x + 30, y: groundY,
          vx: -5 - Math.random() * 5, vy: -1 - Math.random() * 3,
          life: 0.6, size: 2, color: '#fde047'
        });
      }
    }

    if (invincibilityFrames.current > 0) invincibilityFrames.current--;
    if (player.current.boostRemaining > 0) player.current.boostRemaining -= currentSpeed;
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;

    // Obstáculos
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;

      // Hitbox mas agresiva
      const hX = player.current.x + 40;
      const hY = player.current.y + 40;
      const hW = player.current.width - 80;
      const hH = player.current.height - 60;

      if (invincibilityFrames.current === 0 &&
          hX < obs.x + obs.width && hX + hW > obs.x &&
          hY < obs.y + obs.height && hY + hH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 40, obs.y + 50, '#3b82f6');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invincibilityFrames.current = 90; // 1.5s invencible
          lastErrorPhrase.current = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          createExplosion(hX, hY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -100) obstacles.current.splice(index, 1);
    });

    // Colectables
    if (Math.random() < 0.015) {
      collectibles.current.push({ x: width, y: groundY - 180 - Math.random() * 100, width: 40, height: 40 });
    }
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 100 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 100 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 100;
        }
      }
    });

    // Partículas
    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    spawnObstacle(width, height);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo Ciudad Real
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg && bgImg.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      // Overlay oscuro para seriedad
      ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Carretera Anime Pro
    // Arcén
    ctx.fillStyle = '#064e3b';
    ctx.fillRect(0, groundY, width, height - groundY);
    // Asfalto
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);
    // Línea de velocidad
    ctx.strokeStyle = '#f8fafc';
    ctx.lineWidth = 4;
    ctx.setLineDash([100, 200]);
    ctx.lineDashOffset = (distance.current * 15) % 300;
    ctx.beginPath();
    ctx.moveTo(0, groundY + 15); ctx.lineTo(width, groundY + 15);
    ctx.moveTo(0, height - 15); ctx.lineTo(width, height - 15);
    ctx.stroke();
    // Línea Central
    ctx.strokeStyle = '#facc15';
    ctx.lineWidth = 6;
    ctx.setLineDash([40, 60]);
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2); ctx.lineTo(width, groundY + (height - groundY)/2);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;

    // 4. Paneles Solares (Industriales Oscuros)
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height);
      ctx.rotate(obs.tilt);
      // Poste industrial
      ctx.fillStyle = '#334155';
      ctx.fillRect(-8, -40, 16, 80);
      // Panel principal
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#1e3a8a';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height);
      ctx.lineTo(obs.width/2, -obs.height + 20);
      ctx.lineTo(obs.width/2, -30);
      ctx.lineTo(-obs.width/2, -10);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
      // Brillo anime
      ctx.strokeStyle = 'rgba(255,255,255,0.1)';
      ctx.lineWidth = 1;
      for(let i=0; i<5; i++) {
        ctx.beginPath();
        ctx.moveTo(-obs.width/2, -obs.height + (i*15));
        ctx.lineTo(obs.width/2, -obs.height + 20 + (i*15));
        ctx.stroke();
      }
      ctx.restore();
    });

    // 5. Soles
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fbbf24';
      ctx.shadowBlur = 10; ctx.shadowColor = 'orange';
      ctx.beginPath(); ctx.arc(sun.x + 20, sun.y + 20, 20, 0, Math.PI*2); ctx.fill();
      ctx.shadowBlur = 0;
    });

    // 6. Jhonny (Con parpadeo si es invencible)
    if (invincibilityFrames.current % 10 < 5) {
      ctx.save();
      ctx.translate(player.current.x + player.current.width/2, player.current.y + player.current.height/2);
      ctx.rotate(player.current.rotation);
      if (player.current.boostRemaining > 0) {
        ctx.shadowBlur = 20; ctx.shadowColor = '#3b82f6';
      }
      ctx.drawImage(trexImg.current, -player.current.width/2, -player.current.height/2, player.current.width, player.current.height);
      ctx.restore();
    }

    // 7. UI Anime Pro
    ctx.fillStyle = 'rgba(0,0,0,0.7)';
    ctx.fillRect(20, 20, 300, 140);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 300, 140);

    ctx.fillStyle = 'white';
    ctx.font = '24px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current].toUpperCase()}`, 40, 55);
    ctx.font = '20px Bangers';
    ctx.fillText(`DISTANCIA: ${Math.floor(distance.current)}m`, 40, 85);

    // Corazones
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillStyle = i < lives.current ? '#ef4444' : '#4b5563';
      ctx.font = '24px Arial';
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 40 + (i*35), 130);
    }

    // Frase de error flotante
    if (invincibilityFrames.current > 40) {
      ctx.fillStyle = 'white';
      ctx.strokeStyle = 'black';
      ctx.lineWidth = 4;
      ctx.font = 'italic 32px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.strokeText(lastErrorPhrase.current, width/2, 200);
      ctx.fillText(lastErrorPhrase.current, width/2, 200);
    }

    // Mensaje de victoria/ciudad
    if (player.current.guayandoTimer > 0) {
      ctx.save();
      ctx.translate(width/2, height/2 - 100);
      ctx.fillStyle = '#fde047';
      ctx.font = '80px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.strokeText("GUAYANDO!!", 0, 0);
      ctx.fillText("GUAYANDO!!", 0, 0);
      ctx.restore();
    }
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
