import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const obstacleCooldown = useRef(0);

  // Estado para bocadillos
  const [complaint, setComplaint] = useState<{text: string, timer: number} | null>(null);

  const player = useRef({
    x: 120,
    y: 0,
    width: 110, // Más pequeño
    height: 110, // Más pequeño
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.code === 'Space' || e.code === 'ArrowUp')) {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          createExplosion(player.current.x + 30, player.current.y + 100, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<10; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        size: 2 + Math.random() * 4,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.3; // 30% de probabilidad de ser doble
      const obsY = canvasHeight - 150;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 70,
        height: 100,
        tilt: (Math.random() - 0.5) * 0.3
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 120, // Distancia para obligar a doble salto
          y: obsY,
          width: 70,
          height: 100,
          tilt: (Math.random() - 0.5) * 0.3
        });
        obstacleCooldown.current = 100; // Más espacio después de un doble
      } else {
        obstacleCooldown.current = 60; // Espacio normal
      }
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 100;

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 18 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);
    if (nextCityIndex >= BACKGROUND_URLS.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
    }

    // Física de la Motora (Vibración real)
    player.current.y += player.current.dy;
    if (player.current.y + player.current.height < groundY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.04;
      player.current.vibrationY = 0;
    } else {
      player.current.y = groundY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;
      player.current.isJumping = false;
      // Vibración de motor alta frecuencia
      player.current.vibrationY = Math.sin(Date.now() * 0.1) * 2;
      player.current.rotation = Math.sin(Date.now() * 0.05) * 0.02;

      if (Math.random() > 0.6) {
        particles.current.push({
          x: player.current.x + 20, y: groundY,
          vx: -8 - Math.random() * 5, vy: -1 - Math.random() * 2,
          life: 0.5, size: 2, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
      if (Math.random() > 0.4) {
        particles.current.push({
          x: player.current.x, y: player.current.y + 80,
          vx: -15, vy: (Math.random() - 0.5) * 4,
          life: 0.7, size: 6, color: '#3b82f6'
        });
      }
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;

    // Gestión de colisiones
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;

      const pX = player.current.x + 30;
      const pY = player.current.y + 30;
      const pW = player.current.width - 60;
      const pH = player.current.height - 40;

      if (gameActive.current && 
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 40, obs.y + 50, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          setComplaint({text: phrase, timer: 120});
          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -100) obstacles.current.splice(index, 1);
    });

    // Colectables
    if (Math.random() < 0.012) {
      collectibles.current.push({ x: width, y: groundY - 150 - Math.random() * 100, width: 40, height: 40 });
    }
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 100 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 100 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 100;
        }
      }
    });

    // Partículas y Quejas
    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaint) {
      if (complaint.timer > 0) {
        setComplaint({...complaint, timer: complaint.timer - 1});
      } else {
        setComplaint(null);
      }
    }

    spawnObstacles(width, height);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver, complaint]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Carretera Estilo Anime Oscuro
    ctx.fillStyle = '#064e3b'; // Césped oscuro
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#0f172a'; // Asfalto noche
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);

    // Líneas de velocidad central (Motion Blur)
    ctx.strokeStyle = '#facc15';
    ctx.lineWidth = 4;
    ctx.setLineDash([80, 120]);
    ctx.lineDashOffset = (distance.current * 25) % 200;
    ctx.beginPath();
    ctx.moveTo(0, groundY + 50); ctx.lineTo(width, groundY + 50);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Paneles Solares (Industriales)
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height);
      ctx.rotate(obs.tilt);
      ctx.fillStyle = '#334155';
      ctx.fillRect(-6, -40, 12, 60);
      ctx.fillStyle = '#1e293b';
      ctx.strokeStyle = '#1d4ed8';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height);
      ctx.lineTo(obs.width/2, -obs.height + 15);
      ctx.lineTo(obs.width/2, -20);
      ctx.lineTo(-obs.width/2, -10);
      ctx.closePath();
      ctx.fill(); ctx.stroke();
      ctx.restore();
    });

    // 4. Jhonny (La Motora)
    ctx.save();
    ctx.translate(
      player.current.x + player.current.width/2, 
      player.current.y + player.current.height/2 + player.current.vibrationY
    );
    ctx.rotate(player.current.rotation);
    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 25; ctx.shadowColor = '#3b82f6';
    }
    ctx.drawImage(trexImg.current, -player.current.width/2, -player.current.height/2, player.current.width, player.current.height);

    // Bocadillo de Jhonny (GUAYANDO)
    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation); // Nivelar bocadillo
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bX = 50, bY = -60, bW = 100, bH = 40;
      ctx.beginPath();
      ctx.roundRect(bX, bY, bW, bH, 10);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8';
      ctx.font = 'bold 16px Arial';
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", bX + bW/2, bY + 25);
    }
    ctx.restore();

    // 5. Bocadillo de Clientes (Lado Derecho)
    if (complaint) {
      ctx.save();
      const alpha = Math.min(1, complaint.timer / 20);
      ctx.globalAlpha = alpha;
      ctx.fillStyle = '#fef2f2';
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 3;
      const cW = 250, cH = 60;
      const cX = width - cW - 50, cY = 200;
      ctx.beginPath();
      ctx.roundRect(cX, cY, cW, cH, 15);
      ctx.fill(); ctx.stroke();
      // Flecha del bocadillo
      ctx.beginPath();
      ctx.moveTo(cX + cW, cY + 30);
      ctx.lineTo(cX + cW + 20, cY + 40);
      ctx.lineTo(cX + cW, cY + 50);
      ctx.fill(); ctx.stroke();

      ctx.fillStyle = '#b91c1c';
      ctx.font = 'italic 18px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.fillText(complaint.text, cX + cW/2, cY + cH/2 + 7);
      ctx.restore();
    }

    // 6. UI
    ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
    ctx.fillRect(20, 20, 280, 110);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 280, 110);
    ctx.fillStyle = 'white';
    ctx.font = '22px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`ZONA: ${CITIES[currentCityIndex.current]}`, 40, 50);
    ctx.fillText(`MOTORA: ${Math.floor(distance.current)}m`, 40, 80);
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "💀", 40 + (i*30), 110);
    }

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(update);
    return () => window.removeEventListener('resize', handleResize);
  }, [update]);

  return <canvas ref={canvasRef} className="w-full h-full cursor-crosshair" />;
};

