    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.3;
      const obsY = canvasHeight - 145;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 75,
        height: 105,
        tilt: (Math.random() - 0.5) * 0.2
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 180, 
          y: obsY,
          width: 75,
          height: 105,
          tilt: (Math.random() - 0.5) * 0.2
        });
        obstacleCooldown.current = 120;
      } else {
        obstacleCooldown.current = 80;
      }
