    // Física y Squash/Stretch
    player.current.y += player.current.dy;
    if (player.current.y + player.current.height < groundY + 15) { // Un poco de margen para solapamiento
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.03;
