      // Estiramiento en aire
      if (player.current.dy < 0) {
        player.current.squashX = 0.92; player.current.squashY = 1.08;
      } else {
        player.current.squashX = 0.95; player.current.squashY = 1.05;
      }
    } else {
      // Aterrizaje
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.25; 
        player.current.squashY = 0.75;
        player.current.landingTimer = 10;
        createExplosion(player.current.x + 55, groundY + 5, '#cccccc');
      }

      player.current.y = groundY + 15 - player.current.height; // Bajado 15px más para pisar la carretera
      player.current.dy = 0;
      player.current.jumpCount = 0;

      // Suavizar squash de aterrizaje
      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.2;
        player.current.squashY += (1 - player.current.squashY) * 0.2;
      }

      // Vibración de motor reducida y más suave
      player.current.vibrationY = Math.sin(Date.now() * 0.08) * 1.2;
      player.current.rotation = Math.sin(Date.now() * 0.04) * 0.015;

      if (Math.random() > 0.7) {
        particles.current.push({
          x: player.current.x + 20, y: groundY + 10,
          vx: -6 - Math.random() * 4, vy: -1 - Math.random() * 2,
          life: 0.4, size: 2, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
      if (Math.random() > 0.4) {
        particles.current.push({
          x: player.current.x, y: player.current.y + 70,
          vx: -15, vy: (Math.random() - 0.5) * 4,
          life: 0.7, size: 5, color: '#60a5fa'
        });
      }
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;

    // Colisiones
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;

      const pX = player.current.x + 40;
      const pY = player.current.y + 40;
      const pW = player.current.width - 80;
      const pH = player.current.height - 50;

      if (gameActive.current && 
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 40, obs.y + 50, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          setComplaint({text: phrase, timer: 120});
          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -100) obstacles.current.splice(index, 1);
    });

    // Colectables
    if (Math.random() < 0.015) {
      collectibles.current.push({ x: width, y: groundY - 140 - Math.random() * 80, width: 40, height: 40 });
    }
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 80 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 80 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 100;
        }
      }
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaint && complaint.timer > 0) {
      setComplaint({...complaint, timer: complaint.timer - 1});
    } else if (complaint) {
      setComplaint(null);
    }

    spawnObstacles(width, height);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver, complaint]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
      ctx.fillRect(0, 0, width, height);
    }

    // Carteles indicadores cada 100m en el fondo
    const signSpacing = 100;
    const currentDist = distance.current;
    const nextSignDist = Math.ceil(currentDist / signSpacing) * signSpacing;
    for(let i=0; i<3; i++) {
      const signDist = nextSignDist + (i * signSpacing);
      const signX = width - ((signDist - currentDist) * 15) % (width + 200);
      if (signX > -100 && signX < width + 100) {
        ctx.fillStyle = '#1e3a8a';
        ctx.fillRect(signX, groundY - 80, 80, 40);
        ctx.fillStyle = 'white';
        ctx.font = '14px Arial';
        ctx.textAlign = 'center';
        ctx.fillText(`${signDist}m`, signX + 40, groundY - 55);
        ctx.fillStyle = '#334155';
        ctx.fillRect(signX + 35, groundY - 40, 10, 40);
      }
    }

    // 2. Carretera Vibrante
    ctx.fillStyle = '#065f46'; 
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#334155'; // Asfalto gris vivo
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);

    // Línea blanca lateral
    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(0, groundY + 15, width, 5);
    ctx.fillRect(0, height - 15, width, 5);

    // Líneas centrales neón
    ctx.strokeStyle = '#fef08a';
    ctx.lineWidth = 6;
    ctx.setLineDash([60, 100]);
    ctx.lineDashOffset = (distance.current * 30) % 160;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 5); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 5);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Obstáculos
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height);
      ctx.rotate(obs.tilt);
      ctx.fillStyle = '#475569';
      ctx.fillRect(-6, -30, 12, 50);
      ctx.fillStyle = '#1e293b';
      ctx.strokeStyle = '#2563eb';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height);
      ctx.lineTo(obs.width/2, -obs.height + 10);
      ctx.lineTo(obs.width/2, -20);
      ctx.lineTo(-obs.width/2, -10);
      ctx.closePath();
      ctx.fill(); ctx.stroke();
      ctx.restore();
    });

    // 4. Colectables
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fde047';
      ctx.beginPath(); ctx.arc(sun.x + 20, sun.y + 20, 18, 0, Math.PI*2); ctx.fill();
      ctx.strokeStyle = '#ea580c'; ctx.lineWidth = 2; ctx.stroke();
    });

    // 5. Jhonny (Con Squash and Stretch)
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 30; ctx.shadowColor = '#60a5fa';
    }
    // Centramos el dibujo ajustado por el squash
    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);

    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 90, bH = 35;
      ctx.beginPath();
      ctx.roundRect(40, -sH/2 - 20, bW, bH, 8);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 40 + bW/2, -sH/2 + 2);
    }
    ctx.restore();

    // 6. Quejas Clientes (Responsivo y visible)
    if (complaint) {
      ctx.save();
      const alpha = Math.min(1, complaint.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(300, width * 0.8);
      const cH = 70;
      const cX = Math.min(width - cW - 20, width - 20);
      const cY = 160;

      ctx.fillStyle = '#fee2e2';
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.roundRect(width - cW - 20, cY, cW, cH, 20);
      ctx.fill(); ctx.stroke();

      ctx.fillStyle = '#991b1b';
      // Ajuste de fuente dinámico
      const fontSize = cW < 250 ? 14 : 18;
      ctx.font = `italic ${fontSize}px Permanent Marker`;
      ctx.textAlign = 'center';
      ctx.fillText(complaint.text, width - cW/2 - 20, cY + cH/2 + 7);
      ctx.restore();
    }

    // 7. UI Superior
    ctx.fillStyle = 'rgba(15, 23, 42, 0.85)';
    ctx.fillRect(20, 20, 260, 100);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 260, 100);
    ctx.fillStyle = 'white';
    ctx.font = '20px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 40, 45);
    ctx.fillText(`DISTANCIA: ${Math.floor(distance.current)}m`, 40, 75);
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 40 + (i*30), 105);
    }

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(update);
    return () => window.removeEventListener('resize', handleResize);
  }, [update]);

  return <canvas ref={canvasRef} className="w-full h-full cursor-pointer" />;
};

export default Game;

export const GRAVITY = 0.8;
export const JUMP_FORCE = -15;
export const DOUBLE_JUMP_FORCE = -13;
export const BASE_SPEED = 8; 
export const SPEED_INCREMENT = 0.8; // Reducido un poco para que no sea injugable al final
export const METERS_PER_CITY = 500; // Cambio de nivel cada 500m exactos
export const MAX_LIVES = 3;
export const SUNS_FOR_POWERUP = 5;
export const POWERUP_BOOST_DISTANCE = 400;

export const TREX_IMAGE_URL = 'https://i.postimg.cc/mtMKfpYG/trex-jhonny.png';
export const LOGO_IMAGE_URL = 'https://i.postimg.cc/6T5J2v2G/logo.png';

export const BACKGROUND_URLS = [
  "https://wallpaperaccess.com/full/1137576.jpg",
  "https://wallpapers.com/images/hd/puerto-rico-island-aerial-view-xatbur3hk5mja77d.jpg",
  "https://wallpapercave.com/wp/oJ4TXh3.jpg",
  "https://thumbs.dreamstime.com/b/rocky-coast-puerto-rico-14186251.jpg",
  "https://live.staticflickr.com/4384/37192967871_90b4ab467f_b.jpg",
  "https://jetsytravels.com/wp-content/uploads/2019/03/osj-6398.jpg",
  "https://th.bing.com/th/id/R.39bec973b88cf277c453325982ec646a?rik=6cu92l3FdoLrTw&riu=http%3a%2f%2fwallpapercave.com%2fwp%2fEvLKM3D.jpg&ehk=zvMS0Nrclin%2fNQqur66BMer5Q8krY53qS5KUUarJdEU%3d&risl=&pid=ImgRaw&r=0"
];

export const ERROR_PHRASES = [
  "¡Ya no quiero selvicio!",
  "¡Prefiero quedarme con LUMA!",
  "¡Quiero cancelar!",
  "¡Mano, la luz se fue!",
  "¡Esto no prende ni con fe!",
  "¡Ay bendito, otro apagón!"
];

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const obstacleCooldown = useRef(0);

  const [complaint, setComplaint] = useState<{text: string, timer: number} | null>(null);

  const player = useRef({
    x: 120,
    y: 0,
    width: 100, // Ligeramente más pequeño para mejor control
    height: 100,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0,
    squashX: 1,
    squashY: 1,
    landingTimer: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.code === 'Space' || e.code === 'ArrowUp')) {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          player.current.squashX = 0.8;
          player.current.squashY = 1.2;
          createExplosion(player.current.x + 30, player.current.y + 90, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<10; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        size: 2 + Math.random() * 4,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.25;
      const obsY = canvasHeight - 140;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 75,
        height: 105,
        tilt: (Math.random() - 0.5) * 0.15
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 200, 
          y: obsY,
          width: 75,
          height: 105,
          tilt: (Math.random() - 0.5) * 0.15
        });
        obstacleCooldown.current = 140;
      } else {
        obstacleCooldown.current = 90;
      }
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 90; 

    // Calculamos la velocidad actual basándonos en la ciudad actual
    // Añadimos un pequeño boost si está "guayando"
    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 15 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);

    // Victoria
    if (nextCityIndex >= CITIES.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 60; // Mostrar el bocadillo al cambiar de ciudad
    }

    // Física
    player.current.y += player.current.dy;
    // Jhonny debe pisar la carretera, groundY + algo de offset
    const actualFootY = groundY + 15;

    if (player.current.y + player.current.height < actualFootY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.025;
      player.current.vibrationY = 0;
      player.current.squashX = 0.95; player.current.squashY = 1.05;
    } else {
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.3; 
        player.current.squashY = 0.7;
        player.current.landingTimer = 8;
        createExplosion(player.current.x + 50, actualFootY, '#dddddd');
      }

      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;

      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.15;
        player.current.squashY += (1 - player.current.squashY) * 0.15;
      }

      // Vibración suave de motor
      player.current.vibrationY = Math.sin(Date.now() * 0.1) * 1.5;
      player.current.rotation = Math.sin(Date.now() * 0.05) * 0.01;

      if (Math.random() > 0.7) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -5 - Math.random() * 5, vy: -1 - Math.random() * 2,
          life: 0.4, size: 2, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;

    // Colisiones
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      const pX = player.current.x + 35;
      const pY = player.current.y + 35;
      const pW = player.current.width - 70;
      const pH = player.current.height - 40;

      if (gameActive.current && 
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 35, obs.y + 50, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          setComplaint({text: phrase, timer: 120});
          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -200) obstacles.current.splice(index, 1);
    });

    // Colectables
    if (Math.random() < 0.012) {
      collectibles.current.push({ x: width, y: groundY - 140 - Math.random() * 60, width: 40, height: 40 });
    }
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 80 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 80 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 90;
        }
      }
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaint && complaint.timer > 0) {
      setComplaint({...complaint, timer: complaint.timer - 1});
    } else if (complaint) {
      setComplaint(null);
    }

    spawnObstacles(width, height);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver, complaint]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Letreros de Información (Road Signs)
    const currentDist = distance.current;

    // Letreros cada 250m (Mitad y Level Change)
    const signTrigger = 250;
    const lastSignIndex = Math.floor((currentDist - width/30) / signTrigger);
    for(let i = 0; i < 4; i++) {
      const signDist = (lastSignIndex + i) * signTrigger;
      if (signDist < 0) continue;

      const xPos = width - ((signDist - currentDist) * 15) % (width + 500);
      if (xPos > -300 && xPos < width + 300) {
        const isLevelChange = signDist % METERS_PER_CITY === 0;
        const isHalfLevel = signDist % METERS_PER_CITY === 250;

        if (isLevelChange || isHalfLevel) {
          // Poste
          ctx.fillStyle = '#334155';
          ctx.fillRect(xPos + 35, groundY - 50, 10, 50);

          // Señal Verde (Estilo PR)
          ctx.fillStyle = '#065f46';
          ctx.strokeStyle = 'white';
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.roundRect(xPos, groundY - 110, 100, 60, 5);
          ctx.fill(); ctx.stroke();

          ctx.fillStyle = 'white';
          ctx.textAlign = 'center';
          ctx.font = 'bold 12px Arial';

          if (isLevelChange) {
            const nextCity = CITIES[Math.floor(signDist / METERS_PER_CITY)] || "FIN";
            ctx.fillText("PRÓXIMA:", xPos + 50, groundY - 90);
            ctx.font = 'bold 10px Arial';
            ctx.fillText(nextCity.split(' ')[0], xPos + 50, groundY - 70);
          } else {
            ctx.fillText("MITAD DEL", xPos + 50, groundY - 90);
            ctx.fillText("NIVEL", xPos + 50, groundY - 70);
          }

          // Distancia abajo pequeña
          ctx.font = 'italic 10px Arial';
          ctx.fillText(`${signDist}m`, xPos + 50, groundY - 60);
        }
      }
    }

    // 3. Carretera
    ctx.fillStyle = '#064e3b'; // Arcén
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#1e293b'; // Asfalto
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);

    ctx.fillStyle = '#cbd5e1'; // Línea lateral
    ctx.fillRect(0, groundY + 12, width, 4);
    ctx.fillRect(0, height - 12, width, 4);

    ctx.strokeStyle = '#fde047'; // Línea central neón
    ctx.lineWidth = 6;
    ctx.setLineDash([50, 80]);
    ctx.lineDashOffset = (distance.current * 30) % 130;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 5); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 5);
    ctx.stroke();
    ctx.setLineDash([]);

    // 4. Obstáculos
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height);
      ctx.rotate(obs.tilt);
      ctx.fillStyle = '#475569';
      ctx.fillRect(-5, -25, 10, 40);
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height);
      ctx.lineTo(obs.width/2, -obs.height + 8);
      ctx.lineTo(obs.width/2, -15);
      ctx.lineTo(-obs.width/2, -8);
      ctx.closePath();
      ctx.fill(); ctx.stroke();
      ctx.restore();
    });

    // 5. Jhonny
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 20; ctx.shadowColor = '#60a5fa';
    }
    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);

    // Bocadillo Guayando
    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 100, bH = 35;
      ctx.beginPath();
      ctx.roundRect(40, -sH/2 - 25, bW, bH, 8);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 40 + bW/2, -sH/2 - 2);
    }
    ctx.restore();

    // 6. Quejas (Otro lado)
    if (complaint) {
      ctx.save();
      const alpha = Math.min(1, complaint.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(280, width * 0.7);
      const cH = 60;
      ctx.fillStyle = '#fee2e2';
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.roundRect(width - cW - 20, 150, cW, cH, 15);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#991b1b';
      ctx.font = 'italic 16px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.fillText(complaint.text, width - cW/2 - 20, 150 + cH/2 + 5);
      ctx.restore();
    }

    // 7. Soles
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fde047';
      ctx.beginPath(); ctx.arc(sun.x + 20, sun.y + 20, 16, 0, Math.PI*2); ctx.fill();
      ctx.strokeStyle = '#ea580c'; ctx.stroke();
    });

    // 8. UI
    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.fillRect(20, 20, 240, 90);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 240, 90);
    ctx.fillStyle = 'white';
    ctx.font = '18px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 40, 45);
    ctx.fillText(`KM: ${(distance.current / 100).toFixed(1)} / ${(METERS_PER_CITY * CITIES.length / 100).toFixed(1)}`, 40, 70);
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 40 + (i*25), 95);
    }

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(update);
    return () => window.removeEventListener('resize', handleResize);
  }, [update]);

  return <canvas ref={canvasRef} className="w-full h-full cursor-pointer" />;
};

export default Game;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const obstacleCooldown = useRef(0);
  const invulnerableTimer = useRef(0);

  // Usamos refs para el estado de las quejas para evitar que el loop se reinicie al cambiar el estado
  const complaintRef = useRef<{text: string, timer: number} | null>(null);

  // Estado para forzar re-renderizado de la UI de React si fuera necesario, 
  // pero aquí dibujamos todo en el canvas para máxima performance.
  const [, setTick] = useState(0);

  const player = useRef({
    x: 120,
    y: 0,
    width: 100,
    height: 100,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0,
    squashX: 1,
    squashY: 1,
    landingTimer: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if (!gameActive.current) return;
      if ((e.code === 'Space' || e.code === 'ArrowUp')) {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          player.current.squashX = 0.8;
          player.current.squashY = 1.2;
          createExplosion(player.current.x + 30, player.current.y + 90, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<10; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        size: 2 + Math.random() * 4,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.25;
      const obsY = canvasHeight - 140;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 75,
        height: 105,
        tilt: (Math.random() - 0.5) * 0.15
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 220, 
          y: obsY,
          width: 75,
          height: 105,
          tilt: (Math.random() - 0.5) * 0.15
        });
        obstacleCooldown.current = 150;
      } else {
        obstacleCooldown.current = 100;
      }
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 90; 

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 15 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);

    if (nextCityIndex >= CITIES.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 60;
    }

    // Física
    player.current.y += player.current.dy;
    const actualFootY = groundY + 15;

    if (player.current.y + player.current.height < actualFootY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.025;
      player.current.vibrationY = 0;
      player.current.squashX = 0.95; player.current.squashY = 1.05;
    } else {
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.3; 
        player.current.squashY = 0.7;
        player.current.landingTimer = 8;
        createExplosion(player.current.x + 50, actualFootY, '#dddddd');
      }

      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;

      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.15;
        player.current.squashY += (1 - player.current.squashY) * 0.15;
      }

      player.current.vibrationY = Math.sin(Date.now() * 0.1) * 1.5;
      player.current.rotation = Math.sin(Date.now() * 0.05) * 0.01;

      if (Math.random() > 0.7) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -5 - Math.random() * 5, vy: -1 - Math.random() * 2,
          life: 0.4, size: 2, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;
    if (invulnerableTimer.current > 0) invulnerableTimer.current--;

    // Colisiones
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      const pX = player.current.x + 35;
      const pY = player.current.y + 35;
      const pW = player.current.width - 70;
      const pH = player.current.height - 40;

      if (gameActive.current && invulnerableTimer.current === 0 &&
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 35, obs.y + 50, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invulnerableTimer.current = 60; // 1 segundo de invulnerabilidad
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          complaintRef.current = {text: phrase, timer: 120};

          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -200) obstacles.current.splice(index, 1);
    });

    // Colectables
    if (Math.random() < 0.015) {
      collectibles.current.push({ x: width, y: groundY - 140 - Math.random() * 60, width: 40, height: 40 });
    }
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 80 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 80 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 90;
        }
      }
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaintRef.current) {
      if (complaintRef.current.timer > 0) {
        complaintRef.current.timer--;
      } else {
        complaintRef.current = null;
      }
    }

    spawnObstacles(width, height);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]); // Quitamos complaint de las dependencias

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Letreros de Información
    const currentDist = distance.current;
    const signTrigger = 250;
    const lastSignIndex = Math.floor((currentDist - width/30) / signTrigger);
    for(let i = 0; i < 4; i++) {
      const signDist = (lastSignIndex + i) * signTrigger;
      if (signDist < 0) continue;

      const xPos = width - ((signDist - currentDist) * 15) % (width + 500);
      if (xPos > -300 && xPos < width + 300) {
        const isLevelChange = signDist % METERS_PER_CITY === 0;
        const isHalfLevel = signDist % METERS_PER_CITY === 250;

        if (isLevelChange || isHalfLevel) {
          ctx.fillStyle = '#334155';
          ctx.fillRect(xPos + 35, groundY - 50, 10, 50);
          ctx.fillStyle = '#065f46';
          ctx.strokeStyle = 'white';
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.roundRect(xPos, groundY - 110, 100, 60, 5);
          ctx.fill(); ctx.stroke();
          ctx.fillStyle = 'white';
          ctx.textAlign = 'center';
          ctx.font = 'bold 12px Arial';

          if (isLevelChange) {
            const nextCity = CITIES[Math.floor(signDist / METERS_PER_CITY)] || "FIN";
            ctx.fillText("PRÓXIMA:", xPos + 50, groundY - 90);
            ctx.font = 'bold 10px Arial';
            ctx.fillText(nextCity.split(' ')[0], xPos + 50, groundY - 70);
          } else {
            ctx.fillText("MITAD DEL", xPos + 50, groundY - 90);
            ctx.fillText("NIVEL", xPos + 50, groundY - 70);
          }
          ctx.font = 'italic 10px Arial';
          ctx.fillText(`${signDist}m`, xPos + 50, groundY - 60);
        }
      }
    }

    // 3. Carretera
    ctx.fillStyle = '#064e3b';
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);
    ctx.fillStyle = '#cbd5e1';
    ctx.fillRect(0, groundY + 12, width, 4);
    ctx.fillRect(0, height - 12, width, 4);
    ctx.strokeStyle = '#fde047';
    ctx.lineWidth = 6;
    ctx.setLineDash([50, 80]);
    ctx.lineDashOffset = (distance.current * 30) % 130;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 5); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 5);
    ctx.stroke();
    ctx.setLineDash([]);

    // 4. Obstáculos
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height);
      ctx.rotate(obs.tilt);
      ctx.fillStyle = '#475569';
      ctx.fillRect(-5, -25, 10, 40);
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height);
      ctx.lineTo(obs.width/2, -obs.height + 8);
      ctx.lineTo(obs.width/2, -15);
      ctx.lineTo(-obs.width/2, -8);
      ctx.closePath();
      ctx.fill(); ctx.stroke();
      ctx.restore();
    });

    // 5. Jhonny
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);

    // Efecto de parpadeo si es invulnerable
    if (invulnerableTimer.current > 0 && Math.floor(Date.now() / 50) % 2 === 0) {
      ctx.globalAlpha = 0.3;
    }

    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 20; ctx.shadowColor = '#60a5fa';
    }
    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);
    ctx.globalAlpha = 1.0;

    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 100, bH = 35;
      ctx.beginPath();
      ctx.roundRect(40, -sH/2 - 25, bW, bH, 8);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 40 + bW/2, -sH/2 - 2);
    }
    ctx.restore();

    // 6. Quejas (Otro lado)
    if (complaintRef.current) {
      ctx.save();
      const alpha = Math.min(1, complaintRef.current.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(280, width * 0.7);
      const cH = 60;
      ctx.fillStyle = '#fee2e2';
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.roundRect(width - cW - 20, 150, cW, cH, 15);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#991b1b';
      ctx.font = 'italic 16px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.fillText(complaintRef.current.text, width - cW/2 - 20, 150 + cH/2 + 5);
      ctx.restore();
    }

    // 7. Soles
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fde047';
      ctx.beginPath(); ctx.arc(sun.x + 20, sun.y + 20, 16, 0, Math.PI*2); ctx.fill();
      ctx.strokeStyle = '#ea580c'; ctx.stroke();
    });

    // 8. UI
    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.fillRect(20, 20, 240, 90);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 240, 90);
    ctx.fillStyle = 'white';
    ctx.font = '18px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 40, 45);
    ctx.fillText(`KM: ${(distance.current / 100).toFixed(1)} / ${(METERS_PER_CITY * CITIES.length / 100).toFixed(1)}`, 40, 70);
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 40 + (i*25), 95);
    }

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();

    // Iniciar el loop
    requestRef.current = requestAnimationFrame(update);

    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) {
        cancelAnimationFrame(requestRef.current);
      }
    };
  }, [update]);

  return <canvas ref={canvasRef} className="w-full h-full cursor-pointer" />;
};

export default Game;

export const GRAVITY = 0.8;
export const JUMP_FORCE = -15;
export const DOUBLE_JUMP_FORCE = -13;
export const BASE_SPEED = 8; 
export const SPEED_INCREMENT = 0.8; 
export const METERS_PER_CITY = 100; // Cambio cada 100m como solicitado
export const MAX_LIVES = 3;
export const SUNS_FOR_POWERUP = 5;
export const POWERUP_BOOST_DISTANCE = 400;

export const TREX_IMAGE_URL = 'https://i.postimg.cc/mtMKfpYG/trex-jhonny.png';
export const LOGO_IMAGE_URL = 'https://i.postimg.cc/6T5J2v2G/logo.png';

export const BACKGROUND_URLS = [
  "https://wallpaperaccess.com/full/1137576.jpg",
  "https://wallpapers.com/images/hd/puerto-rico-island-aerial-view-xatbur3hk5mja77d.jpg",
  "https://wallpapercave.com/wp/oJ4TXh3.jpg",
  "https://thumbs.dreamstime.com/b/rocky-coast-puerto-rico-14186251.jpg",
  "https://live.staticflickr.com/4384/37192967871_90b4ab467f_b.jpg",
  "https://jetsytravels.com/wp-content/uploads/2019/03/osj-6398.jpg",
  "https://th.bing.com/th/id/R.39bec973b88cf277c453325982ec646a?rik=6cu92l3FdoLrTw&riu=http%3a%2f%2fwallpapercave.com%2fwp%2fEvLKM3D.jpg&ehk=zvMS0Nrclin%2fNQqur66BMer5Q8krY53qS5KUUarJdEU%3d&risl=&pid=ImgRaw&r=0"
];

export const ERROR_PHRASES = [
  "¡Ya no quiero selvicio!",
  "¡Prefiero quedarme con LUMA!",
  "¡Quiero cancelar!",
  "¡Mano, la luz se fue!",
  "¡Esto no prende ni con fe!",
  "¡Ay bendito, otro apagón!"
];

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const obstacleCooldown = useRef(0);
  const invulnerableTimer = useRef(0);

  const complaintRef = useRef<{text: string, timer: number} | null>(null);
  const [, setTick] = useState(0);

  const player = useRef({
    x: 120,
    y: 0,
    width: 100,
    height: 100,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0,
    squashX: 1,
    squashY: 1,
    landingTimer: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if (!gameActive.current) return;
      if ((e.code === 'Space' || e.code === 'ArrowUp')) {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          player.current.squashX = 0.8;
          player.current.squashY = 1.2;
          createExplosion(player.current.x + 30, player.current.y + 90, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<10; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        size: 2 + Math.random() * 4,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.25;
      const obsY = canvasHeight - 140;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 75,
        height: 105,
        tilt: (Math.random() - 0.5) * 0.15
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 220, 
          y: obsY,
          width: 75,
          height: 105,
          tilt: (Math.random() - 0.5) * 0.15
        });
        obstacleCooldown.current = 150;
      } else {
        obstacleCooldown.current = 100;
      }
    }
  };

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 90; 

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 15 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);

    if (nextCityIndex >= CITIES.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 60;
    }

    // Física
    player.current.y += player.current.dy;
    const actualFootY = groundY + 15;

    if (player.current.y + player.current.height < actualFootY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.025;
      player.current.vibrationY = 0;
      player.current.squashX = 0.95; player.current.squashY = 1.05;
    } else {
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.3; 
        player.current.squashY = 0.7;
        player.current.landingTimer = 8;
        createExplosion(player.current.x + 50, actualFootY, '#dddddd');
      }

      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;

      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.15;
        player.current.squashY += (1 - player.current.squashY) * 0.15;
      }

      player.current.vibrationY = Math.sin(Date.now() * 0.1) * 1.5;
      player.current.rotation = Math.sin(Date.now() * 0.05) * 0.01;

      if (Math.random() > 0.7) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -5 - Math.random() * 5, vy: -1 - Math.random() * 2,
          life: 0.4, size: 2, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;
    if (invulnerableTimer.current > 0) invulnerableTimer.current--;

    // Colisiones
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      const pX = player.current.x + 35;
      const pY = player.current.y + 35;
      const pW = player.current.width - 70;
      const pH = player.current.height - 40;

      if (gameActive.current && invulnerableTimer.current === 0 &&
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 35, obs.y + 50, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invulnerableTimer.current = 60;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          complaintRef.current = {text: phrase, timer: 120};

          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -200) obstacles.current.splice(index, 1);
    });

    // Colectables
    if (Math.random() < 0.015) {
      collectibles.current.push({ x: width, y: groundY - 140 - Math.random() * 60, width: 40, height: 40 });
    }
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 80 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 80 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 90;
        }
      }
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaintRef.current) {
      if (complaintRef.current.timer > 0) {
        complaintRef.current.timer--;
      } else {
        complaintRef.current = null;
      }
    }

    spawnObstacles(width, height);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Carretera
    ctx.fillStyle = '#064e3b';
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);
    ctx.fillStyle = '#cbd5e1';
    ctx.fillRect(0, groundY + 12, width, 4);
    ctx.fillRect(0, height - 12, width, 4);
    ctx.strokeStyle = '#fde047';
    ctx.lineWidth = 6;
    ctx.setLineDash([50, 80]);
    ctx.lineDashOffset = (distance.current * 30) % 130;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 5); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 5);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Obstáculos
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height);
      ctx.rotate(obs.tilt);
      ctx.fillStyle = '#475569';
      ctx.fillRect(-5, -25, 10, 40);
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height);
      ctx.lineTo(obs.width/2, -obs.height + 8);
      ctx.lineTo(obs.width/2, -15);
      ctx.lineTo(-obs.width/2, -8);
      ctx.closePath();
      ctx.fill(); ctx.stroke();
      ctx.restore();
    });

    // 4. Jhonny
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (invulnerableTimer.current > 0 && Math.floor(Date.now() / 50) % 2 === 0) {
      ctx.globalAlpha = 0.3;
    }
    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 20; ctx.shadowColor = '#60a5fa';
    }
    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);
    ctx.globalAlpha = 1.0;

    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 100, bH = 35;
      ctx.beginPath();
      ctx.roundRect(40, -sH/2 - 25, bW, bH, 8);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 40 + bW/2, -sH/2 - 2);
    }
    ctx.restore();

    // 5. Quejas
    if (complaintRef.current) {
      ctx.save();
      const alpha = Math.min(1, complaintRef.current.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(280, width * 0.7);
      const cH = 60;
      ctx.fillStyle = '#fee2e2';
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.roundRect(width - cW - 20, 150, cW, cH, 15);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#991b1b';
      ctx.font = 'italic 16px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.fillText(complaintRef.current.text, width - cW/2 - 20, 150 + cH/2 + 5);
      ctx.restore();
    }

    // 6. Soles
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fde047';
      ctx.beginPath(); ctx.arc(sun.x + 20, sun.y + 20, 16, 0, Math.PI*2); ctx.fill();
      ctx.strokeStyle = '#ea580c'; ctx.stroke();
    });

    // 7. UI Principal
    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.fillRect(20, 20, 240, 105);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 240, 105);
    ctx.fillStyle = 'white';
    ctx.font = '18px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 40, 45);
    ctx.fillText(`METROS: ${Math.floor(distance.current)}m`, 40, 65);
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 40 + (i*25), 85);
    }

    // 8. Barra de Progreso (Nueva)
    const totalDistance = METERS_PER_CITY * CITIES.length;
    const progress = Math.min(1, distance.current / totalDistance);
    const barW = 200, barH = 10;
    ctx.fillStyle = '#334155';
    ctx.fillRect(40, 100, barW, barH);
    ctx.fillStyle = '#3b82f6';
    ctx.fillRect(40, 100, barW * progress, barH);
    ctx.strokeStyle = 'white';
    ctx.lineWidth = 1;
    ctx.strokeRect(40, 100, barW, barH);

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    requestRef.current = requestAnimationFrame(update);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [update]);

  return <canvas ref={canvasRef} className="w-full h-full cursor-pointer" />;
};

export default Game;

import React from 'react';
import { METERS_PER_CITY, BACKGROUND_URLS } from '../constants';
import { CITIES } from '../types';

interface GameOverProps {
  score: number;
  distance: number;
  city: string;
  onRestart: () => void;
  win?: boolean;
}

const GameOver: React.FC<GameOverProps> = ({ score, distance, city, onRestart, win }) => {
  const totalGoal = METERS_PER_CITY * CITIES.length;
  const progressPercent = Math.min(100, Math.floor((distance / totalGoal) * 100));

  return (
    <div className="absolute inset-0 z-40 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
      <div className={`bg-white rounded-3xl p-6 sm:p-10 max-w-lg w-full border-8 ${win ? 'border-yellow-400' : 'border-red-600'} shadow-2xl text-center overflow-hidden`}>
        {win ? (
          <>
            <h2 className="text-4xl sm:text-6xl font-cartoon text-yellow-600 mb-4 animate-pulse">¡¡¡LEYENDA SOLAR!!!</h2>
            <p className="text-lg sm:text-2xl font-graffiti text-blue-700 mb-6 italic">
              ¡Pudiste llevar energía renovable a toda la isla!
            </p>
          </>
        ) : (
          <>
            <h2 className="text-4xl sm:text-6xl font-cartoon text-red-600 mb-4 uppercase">¡APAGÓN TOTAL!</h2>
            <p className="text-lg sm:text-xl font-graffiti text-gray-600 mb-6 italic">
              "LUMA te lo advirtió..."
            </p>
          </>
        )}

        <div className="grid grid-cols-2 gap-4 mb-6 bg-gray-100 p-4 sm:p-6 rounded-2xl">
          <div className="text-left overflow-hidden">
            <span className="block text-xs font-bold text-gray-500 uppercase">DISTANCIA</span>
            <span className="text-xl sm:text-3xl font-cartoon text-blue-600">{distance}m</span>
          </div>
          <div className="text-left overflow-hidden">
            <span className="block text-xs font-bold text-gray-500 uppercase">ÚLTIMA CIUDAD</span>
            <span className="text-lg sm:text-2xl font-cartoon text-emerald-600 leading-tight block truncate">
              {city.split(' (')[0]}
            </span>
          </div>
        </div>

        <div className="mb-8 px-2">
          <div className="flex justify-between text-xs font-bold text-gray-500 mb-1">
            <span>PROGRESO DE LA ISLA</span>
            <span>{progressPercent}%</span>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-6 border-2 border-gray-300 overflow-hidden">
            <div 
              className={`h-full transition-all duration-1000 ${win ? 'bg-yellow-400' : 'bg-blue-500'}`} 
              style={{ width: `${progressPercent}%` }}
            ></div>
          </div>
          <p className="text-[10px] sm:text-xs text-gray-400 mt-2 uppercase tracking-tighter">
            {win ? "META ALCANZADA - 100% RENOVABLE" : `TE FALTARON ${totalGoal - distance}m PARA LA META`}
          </p>
        </div>

        <button 
          onClick={onRestart}
          className={`w-full py-4 sm:py-5 ${win ? 'bg-yellow-500' : 'bg-red-600'} text-white font-cartoon text-3xl sm:text-4xl rounded-2xl shadow-xl hover:scale-105 transition active:scale-95 border-b-8 ${win ? 'border-yellow-800' : 'border-red-900'}`}
        >
          {win ? "¡REINICIAR TOUR!" : "OTRA OPORTUNIDAD"}
        </button>
      </div>
    </div>
  );
};

export default GameOver;

import React, { useState } from 'react';
import { GameState, CITIES } from './types';
import Game from './components/Game';
import Menu from './components/Menu';
import GameOver from './components/GameOver';
import { LOGO_IMAGE_URL, TREX_IMAGE_URL } from './constants';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [distance, setDistance] = useState(0);
  const [finalCity, setFinalCity] = useState(CITIES[0]);
  const [isWin, setIsWin] = useState(false);

  const startGame = () => {
    setGameState(GameState.PLAYING);
    setScore(0);
    setDistance(0);
    setIsWin(false);
  };

  const endGame = (finalScore: number, finalDist: number, city: string, win?: boolean) => {
    setScore(finalScore);
    setDistance(Math.floor(finalDist));
    setFinalCity(city);
    setIsWin(!!win);
    setGameState(win ? GameState.WIN : GameState.GAMEOVER);
  };

  return (
    <div className="min-h-screen w-full bg-[#0f172a] flex flex-col items-center justify-center p-4 sm:p-8 select-none overflow-y-auto">
      {/* HEADER: Outside the game box */}
      <header className="flex flex-row items-center justify-center gap-4 mb-6 w-full max-w-5xl">
        <h1 className="text-5xl sm:text-7xl font-cartoon text-blue-500 drop-shadow-[0_5px_0_rgba(29,78,216,1)] tracking-tighter">
          SOLAR BIKER
        </h1>
        <img 
          src={TREX_IMAGE_URL} 
          alt="Jhonny" 
          className="h-16 sm:h-24 w-auto drop-shadow-2xl animate-bounce" 
          style={{ animationDuration: '3s' }}
        />
      </header>

      {/* GAME FRAME: The enclosed box */}
      <main className="relative w-full max-w-5xl aspect-[16/9] bg-black border-[10px] sm:border-[16px] border-[#1e293b] rounded-3xl shadow-[0_0_60px_rgba(59,130,246,0.25)] overflow-hidden ring-4 ring-blue-600/20">
        {gameState === GameState.MENU && <Menu onStart={startGame} />}
        {gameState === GameState.PLAYING && <Game onGameOver={endGame} />}
        {(gameState === GameState.GAMEOVER || gameState === GameState.WIN) && (
          <GameOver 
            score={score} 
            distance={distance} 
            city={finalCity} 
            onRestart={startGame} 
            win={isWin}
          />
        )}

        {/* Frame Decoration: Corners */}
        <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-blue-500 m-2 rounded-tl-lg opacity-50 pointer-events-none"></div>
        <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-blue-500 m-2 rounded-tr-lg opacity-50 pointer-events-none"></div>
        <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-blue-500 m-2 rounded-bl-lg opacity-50 pointer-events-none"></div>
        <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-blue-500 m-2 rounded-br-lg opacity-50 pointer-events-none"></div>
      </main>

      {/* FOOTER: Controls and Copyright */}
      <footer className="mt-8 flex flex-col items-center gap-2 text-center">
        <div className="bg-[#1e293b] px-6 py-3 rounded-2xl border-2 border-blue-500/30 shadow-lg">
          <p className="font-cartoon text-xl sm:text-2xl text-yellow-400 tracking-wide">
            CONTROLES: <span className="text-white bg-slate-700 px-2 py-0.5 rounded border border-slate-500">ESPACIO</span> SALTO / DOBLE SALTO
          </p>
        </div>
        <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.2em] mt-2 opacity-60">
          Copyright © 2025 Solar Biker - Puerto Rico. Jhonny & LUMA Out.
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>(0);

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const obstacleCooldown = useRef(0);
  const collectibleCooldown = useRef(0);
  const invulnerableTimer = useRef(0);

  const complaintRef = useRef<{text: string, timer: number} | null>(null);

  const player = useRef({
    x: 120,
    y: 0,
    width: 100,
    height: 100,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0,
    squashX: 1,
    squashY: 1,
    landingTimer: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if (!gameActive.current) return;
      if ((e.code === 'Space' || e.code === 'ArrowUp')) {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          player.current.squashX = 0.8;
          player.current.squashY = 1.2;
          createExplosion(player.current.x + 30, player.current.y + 90, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<10; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        size: 2 + Math.random() * 4,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.25;
      const obsY = canvasHeight - 140;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 80,
        height: 100,
        tilt: (Math.random() - 0.5) * 0.1
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 240, 
          y: obsY,
          width: 80,
          height: 100,
          tilt: (Math.random() - 0.5) * 0.1
        });
        obstacleCooldown.current = 160;
      } else {
        obstacleCooldown.current = 110;
      }
    }
  };

  const spawnCollectibles = (canvasWidth: number, canvasHeight: number, groundY: number) => {
    if (collectibleCooldown.current > 0) {
      collectibleCooldown.current--;
      return;
    }

    if (Math.random() < 0.015) {
      collectibles.current.push({ 
        x: canvasWidth, 
        y: groundY - 140 - Math.random() * 80, 
        width: 40, 
        height: 40 
      });
      // Spacing distribution: Don't allow another sun immediately
      collectibleCooldown.current = 40 + Math.random() * 60;
    }
  }

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 90; 

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 15 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);

    if (nextCityIndex >= CITIES.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 60;
    }

    // Física
    player.current.y += player.current.dy;
    const actualFootY = groundY + 15;

    if (player.current.y + player.current.height < actualFootY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.025;
      player.current.vibrationY = 0;
      player.current.squashX = 0.95; player.current.squashY = 1.05;
    } else {
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.3; 
        player.current.squashY = 0.7;
        player.current.landingTimer = 8;
        createExplosion(player.current.x + 50, actualFootY, '#dddddd');
      }

      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;

      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.15;
        player.current.squashY += (1 - player.current.squashY) * 0.15;
      }

      player.current.vibrationY = Math.sin(Date.now() * 0.1) * 1.5;
      player.current.rotation = Math.sin(Date.now() * 0.05) * 0.01;

      if (Math.random() > 0.7) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -5 - Math.random() * 5, vy: -1 - Math.random() * 2,
          life: 0.4, size: 2, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;
    if (invulnerableTimer.current > 0) invulnerableTimer.current--;

    // Colisiones
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      const pX = player.current.x + 35;
      const pY = player.current.y + 35;
      const pW = player.current.width - 70;
      const pH = player.current.height - 40;

      if (gameActive.current && invulnerableTimer.current === 0 &&
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 40, obs.y + 50, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invulnerableTimer.current = 60;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          complaintRef.current = {text: phrase, timer: 120};

          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -200) obstacles.current.splice(index, 1);
    });

    // Colectables
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 40 && player.current.x + 80 > item.x &&
          player.current.y < item.y + 40 && player.current.y + 80 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 90;
        }
      }
      if (item.x + item.width < -100) collectibles.current.splice(index, 1);
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.02;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaintRef.current) {
      if (complaintRef.current.timer > 0) {
        complaintRef.current.timer--;
      } else {
        complaintRef.current = null;
      }
    }

    spawnObstacles(width, height);
    spawnCollectibles(width, height, groundY);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Carretera
    ctx.fillStyle = '#064e3b';
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);
    ctx.fillStyle = '#cbd5e1';
    ctx.fillRect(0, groundY + 12, width, 4);
    ctx.fillRect(0, height - 12, width, 4);
    ctx.strokeStyle = '#fde047';
    ctx.lineWidth = 6;
    ctx.setLineDash([50, 80]);
    ctx.lineDashOffset = (distance.current * 30) % 130;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 5); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 5);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Obstáculos: Paneles solares sin base
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height/2);
      ctx.rotate(obs.tilt);

      // Panel principal
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.rect(-obs.width/2, -obs.height/2, obs.width, obs.height);
      ctx.fill(); ctx.stroke();

      // Dibujar la cuadrícula interna del panel
      ctx.strokeStyle = 'rgba(59, 130, 246, 0.4)';
      ctx.lineWidth = 1;
      // Líneas verticales
      for(let i = 1; i < 4; i++) {
        const lx = -obs.width/2 + (obs.width / 4) * i;
        ctx.beginPath();
        ctx.moveTo(lx, -obs.height/2);
        ctx.lineTo(lx, obs.height/2);
        ctx.stroke();
      }
      // Líneas horizontales
      for(let i = 1; i < 6; i++) {
        const ly = -obs.height/2 + (obs.height / 6) * i;
        ctx.beginPath();
        ctx.moveTo(-obs.width/2, ly);
        ctx.lineTo(obs.width/2, ly);
        ctx.stroke();
      }

      // Brillo del borde superior
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(-obs.width/2, -obs.height/2);
      ctx.lineTo(obs.width/2, -obs.height/2);
      ctx.stroke();

      ctx.restore();
    });

    // 4. Jhonny
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (invulnerableTimer.current > 0 && Math.floor(Date.now() / 50) % 2 === 0) {
      ctx.globalAlpha = 0.3;
    }
    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 20; ctx.shadowColor = '#60a5fa';
    }
    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);
    ctx.globalAlpha = 1.0;

    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 100, bH = 35;
      ctx.beginPath();
      ctx.roundRect(40, -sH/2 - 25, bW, bH, 8);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 40 + bW/2, -sH/2 - 2);
    }
    ctx.restore();

    // 5. Quejas
    if (complaintRef.current) {
      ctx.save();
      const alpha = Math.min(1, complaintRef.current.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(280, width * 0.7);
      const cH = 60;
      ctx.fillStyle = '#fee2e2';
      ctx.strokeStyle = '#ef4444';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.roundRect(width - cW - 20, 150, cW, cH, 15);
      ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#991b1b';
      ctx.font = 'italic 16px Permanent Marker';
      ctx.textAlign = 'center';
      ctx.fillText(complaintRef.current.text, width - cW/2 - 20, 150 + cH/2 + 5);
      ctx.restore();
    }

    // 6. Soles
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fde047';
      ctx.beginPath(); ctx.arc(sun.x + 20, sun.y + 20, 16, 0, Math.PI*2); ctx.fill();
      ctx.strokeStyle = '#ea580c'; ctx.stroke();

      // Pequeño brillo central
      ctx.fillStyle = 'white';
      ctx.beginPath(); ctx.arc(sun.x + 14, sun.y + 14, 4, 0, Math.PI*2); ctx.fill();
    });

    // 7. UI Principal
    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.fillRect(20, 20, 240, 105);
    ctx.strokeStyle = '#3b82f6';
    ctx.strokeRect(20, 20, 240, 105);
    ctx.fillStyle = 'white';
    ctx.font = '18px Bangers';
    ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 40, 45);
    ctx.fillText(`METROS: ${Math.floor(distance.current)}m`, 40, 65);
    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 40 + (i*25), 85);
    }

    // 8. Barra de Progreso
    const totalDistance = METERS_PER_CITY * CITIES.length;
    const progress = Math.min(1, distance.current / totalDistance);
    const barW = 200, barH = 10;
    ctx.fillStyle = '#334155';
    ctx.fillRect(40, 100, barW, barH);
    ctx.fillStyle = '#3b82f6';
    ctx.fillRect(40, 100, barW * progress, barH);
    ctx.strokeStyle = 'white';
    ctx.lineWidth = 1;
    ctx.strokeRect(40, 100, barW, barH);

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        // Fit canvas to parent container (the frame)
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };

    // Initial size
    handleResize();

    window.addEventListener('resize', handleResize);
    requestRef.current = requestAnimationFrame(update);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [update]);

  return (
    <div ref={containerRef} className="w-full h-full relative">
      <canvas ref={canvasRef} className="w-full h-full block cursor-pointer" />
    </div>
  );
};

export default Game;

export const GRAVITY = 0.8;
export const JUMP_FORCE = -15;
export const DOUBLE_JUMP_FORCE = -13;
export const BASE_SPEED = 7; 
export const SPEED_INCREMENT = 0.6; 
export const METERS_PER_CITY = 100;
export const MAX_LIVES = 3;
export const SUNS_FOR_POWERUP = 5;
export const POWERUP_BOOST_DISTANCE = 500;

export const TREX_IMAGE_URL = 'https://i.postimg.cc/mtMKfpYG/trex-jhonny.png';
export const LOGO_IMAGE_URL = 'https://i.postimg.cc/6T5J2v2G/logo.png';
export const WINDMAR_LOGO_URL = 'https://windmarhome.com/wp-content/uploads/2022/10/Windmar-Home-Logo-White.png';

export const BACKGROUND_URLS = [
  "https://wallpaperaccess.com/full/1137576.jpg",
  "https://wallpapers.com/images/hd/puerto-rico-island-aerial-view-xatbur3hk5mja77d.jpg",
  "https://wallpapercave.com/wp/oJ4TXh3.jpg",
  "https://thumbs.dreamstime.com/b/rocky-coast-puerto-rico-14186251.jpg",
  "https://live.staticflickr.com/4384/37192967871_90b4ab467f_b.jpg",
  "https://jetsytravels.com/wp-content/uploads/2019/03/osj-6398.jpg",
  "https://th.bing.com/th/id/R.39bec973b88cf277c453325982ec646a?rik=6cu92l3FdoLrTw&riu=http%3a%2f%2fwallpapercave.com%2fwp%2fEvLKM3D.jpg&ehk=zvMS0Nrclin%2fNQqur66BMer5Q8krY53qS5KUUarJdEU%3d&risl=&pid=ImgRaw&r=0"
];

export const ERROR_PHRASES = [
  "¡Ya no quiero selvicio!",
  "¡Prefiero quedarme con LUMA!",
  "¡Quiero cancelar!",
  "¡Mano, la luz se fue!",
  "¡Esto no prende ni con fe!",
  "¡Ay bendito, otro apagón!"
];

import React, { useState } from 'react';
import { GameState, CITIES } from './types';
import Game from './components/Game';
import Menu from './components/Menu';
import GameOver from './components/GameOver';
import { TREX_IMAGE_URL } from './constants';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [distance, setDistance] = useState(0);
  const [finalCity, setFinalCity] = useState(CITIES[0]);
  const [isWin, setIsWin] = useState(false);

  const startGame = () => {
    setGameState(GameState.PLAYING);
    setScore(0);
    setDistance(0);
    setIsWin(false);
  };

  const endGame = (finalScore: number, finalDist: number, city: string, win?: boolean) => {
    setScore(finalScore);
    setDistance(Math.floor(finalDist));
    setFinalCity(city);
    setIsWin(!!win);
    setGameState(win ? GameState.WIN : GameState.GAMEOVER);
  };

  return (
    <div className="min-h-screen w-full bg-[#0f172a] flex flex-col items-center justify-start py-6 px-4 sm:px-8 select-none overflow-y-auto overflow-x-hidden">
      {/* HEADER: Fuera del marco del juego */}
      <header className="flex flex-row items-center justify-center gap-6 mb-4 w-full max-w-6xl">
        <h1 className="text-4xl sm:text-7xl font-cartoon text-blue-500 drop-shadow-[0_4px_0_rgba(29,78,216,1)] tracking-tighter uppercase">
          Solar Biker
        </h1>
        <div className="relative">
          <img 
            src={TREX_IMAGE_URL} 
            alt="Jhonny" 
            className="h-16 sm:h-24 w-auto drop-shadow-[0_10px_10px_rgba(0,0,0,0.5)] animate-bounce" 
            style={{ animationDuration: '2.5s' }}
          />
          <div className="absolute -bottom-2 -right-2 bg-yellow-400 text-blue-900 text-[10px] font-bold px-2 py-0.5 rounded-full border border-blue-900 shadow-sm rotate-12">
            Jhonny PR
          </div>
        </div>
      </header>

      {/* MARCO DEL JUEGO: Rectangular ajustado para PC */}
      <main className="relative w-full max-w-6xl h-auto aspect-[21/9] sm:aspect-[2.4/1] bg-black border-[6px] sm:border-[12px] border-[#1e293b] rounded-[2rem] shadow-[0_25px_50px_-12px_rgba(0,0,0,0.8),0_0_80px_rgba(59,130,246,0.15)] overflow-hidden ring-2 ring-blue-500/20">
        <div className="w-full h-full relative">
          {gameState === GameState.MENU && <Menu onStart={startGame} />}
          {gameState === GameState.PLAYING && <Game onGameOver={endGame} />}
          {(gameState === GameState.GAMEOVER || gameState === GameState.WIN) && (
            <GameOver 
              score={score} 
              distance={distance} 
              city={finalCity} 
              onRestart={startGame} 
              win={isWin}
            />
          )}
        </div>

        {/* Adornos del marco */}
        <div className="absolute top-4 left-4 w-12 h-12 border-t-2 border-l-2 border-blue-500/30 rounded-tl-xl pointer-events-none"></div>
        <div className="absolute top-4 right-4 w-12 h-12 border-t-2 border-r-2 border-blue-500/30 rounded-tr-xl pointer-events-none"></div>
        <div className="absolute bottom-4 left-4 w-12 h-12 border-b-2 border-l-2 border-blue-500/30 rounded-bl-xl pointer-events-none"></div>
        <div className="absolute bottom-4 right-4 w-12 h-12 border-b-2 border-r-2 border-blue-500/30 rounded-br-xl pointer-events-none"></div>
      </main>

      {/* FOOTER: Controles y Copyright fuera del marco */}
      <footer className="mt-6 flex flex-col items-center gap-4 w-full max-w-4xl">
        <div className="flex flex-wrap justify-center gap-3">
          <div className="bg-slate-800/80 backdrop-blur-sm px-5 py-2 rounded-full border border-blue-500/40 shadow-xl flex items-center gap-3">
            <span className="bg-blue-600 text-white font-bold px-2 py-0.5 rounded text-sm shadow-sm">ESPACIO</span>
            <span className="font-cartoon text-lg text-blue-200 tracking-wide">SALTAR</span>
          </div>
          <div className="bg-slate-800/80 backdrop-blur-sm px-5 py-2 rounded-full border border-yellow-500/40 shadow-xl flex items-center gap-3">
            <span className="text-yellow-400 text-xl">☀️</span>
            <span className="font-cartoon text-lg text-yellow-100 tracking-wide">5 SOLES = NITRO WINDMAR</span>
          </div>
        </div>

        <div className="text-center">
          <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.3em] opacity-80">
            © 2025 SOLAR BIKER PROJECT | POWERED BY WINDMAR HOME
          </p>
          <p className="text-blue-500/40 text-[9px] mt-1 font-mono">
            ESTACIÓN: PUERTO RICO - TODA LA ISLA CONECTADA
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  SUNS_FOR_POWERUP, 
  TREX_IMAGE_URL,
  WINDMAR_LOGO_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>(0);

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES);
  const obstacleCooldown = useRef(0);
  const collectibleCooldown = useRef(0);
  const invulnerableTimer = useRef(0);

  const complaintRef = useRef<{text: string, timer: number} | null>(null);

  const player = useRef({
    x: 150,
    y: 0,
    width: 90,
    height: 90,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0,
    squashX: 1,
    squashY: 1,
    landingTimer: 0
  });

  const obstacles = useRef<any[]>([]);
  const collectibles = useRef<any[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const windmarImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    windmarImg.current.src = WINDMAR_LOGO_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if (!gameActive.current) return;
      if (e.code === 'Space' || e.code === 'ArrowUp') {
        if (player.current.jumpCount < 2) {
          player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
          player.current.jumpCount++;
          player.current.isJumping = true;
          player.current.squashX = 0.8;
          player.current.squashY = 1.2;
          createExplosion(player.current.x + 30, player.current.y + 80, '#ffffff');
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, []);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<8; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 8,
        vy: (Math.random() - 0.5) * 8,
        life: 1.0,
        size: 2 + Math.random() * 3,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.02) {
      const isDouble = Math.random() < 0.2;
      const obsY = canvasHeight - 130;

      obstacles.current.push({
        x: canvasWidth,
        y: obsY,
        width: 70,
        height: 90,
        tilt: (Math.random() - 0.5) * 0.08
      });

      if (isDouble) {
        obstacles.current.push({
          x: canvasWidth + 280, 
          y: obsY,
          width: 70,
          height: 90,
          tilt: (Math.random() - 0.5) * 0.08
        });
        obstacleCooldown.current = 180;
      } else {
        obstacleCooldown.current = 120;
      }
    }
  };

  const spawnCollectibles = (canvasWidth: number, canvasHeight: number, groundY: number) => {
    if (collectibleCooldown.current > 0) {
      collectibleCooldown.current--;
      return;
    }

    // Distribución más espaciada y aleatoria en altura
    if (Math.random() < 0.015) {
      collectibles.current.push({ 
        x: canvasWidth, 
        y: groundY - 120 - Math.random() * 120, 
        width: 35, 
        height: 35 
      });
      collectibleCooldown.current = 60 + Math.random() * 80;
    }
  }

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 70; 

    const currentSpeed = BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 12 : 0);
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);

    if (nextCityIndex >= CITIES.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 60;
    }

    // Física
    player.current.y += player.current.dy;
    const actualFootY = groundY + 10;

    if (player.current.y + player.current.height < actualFootY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.02;
      player.current.vibrationY = 0;
    } else {
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.25; 
        player.current.squashY = 0.75;
        player.current.landingTimer = 6;
        createExplosion(player.current.x + 40, actualFootY, '#dddddd');
      }

      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;

      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.2;
        player.current.squashY += (1 - player.current.squashY) * 0.2;
      }

      player.current.vibrationY = Math.sin(Date.now() * 0.12) * 1.2;
      player.current.rotation = Math.sin(Date.now() * 0.06) * 0.01;

      if (Math.random() > 0.8) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -4 - Math.random() * 4, vy: -1 - Math.random() * 1.5,
          life: 0.3, size: 1.5, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;
    if (invulnerableTimer.current > 0) invulnerableTimer.current--;

    // Colisiones Obstáculos
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      const pX = player.current.x + 30;
      const pY = player.current.y + 30;
      const pW = player.current.width - 60;
      const pH = player.current.height - 35;

      if (gameActive.current && invulnerableTimer.current === 0 &&
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 35, obs.y + 45, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invulnerableTimer.current = 60;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          complaintRef.current = {text: phrase, timer: 120};
          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -200) obstacles.current.splice(index, 1);
    });

    // Colisiones Colectables
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + 35 && player.current.x + 70 > item.x &&
          player.current.y < item.y + 35 && player.current.y + 70 > item.y) {
        collectibles.current.splice(index, 1);
        sunsCollected.current++;
        totalScore.current += 100;
        if (sunsCollected.current % SUNS_FOR_POWERUP === 0) {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 90;
        }
      }
      if (item.x + item.width < -100) collectibles.current.splice(index, 1);
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.025;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaintRef.current) {
      if (complaintRef.current.timer > 0) complaintRef.current.timer--;
      else complaintRef.current = null;
    }

    spawnObstacles(width, height);
    spawnCollectibles(width, height, groundY);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo Ciudad
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.45)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Carretera
    ctx.fillStyle = '#064e3b';
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, groundY + 8, width, height - groundY - 8);
    ctx.fillStyle = '#cbd5e1';
    ctx.fillRect(0, groundY + 10, width, 3);
    ctx.fillRect(0, height - 10, width, 3);
    ctx.strokeStyle = '#fde047';
    ctx.lineWidth = 4;
    ctx.setLineDash([40, 60]);
    ctx.lineDashOffset = (distance.current * 30) % 100;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 2); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 2);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Obstáculos: Paneles solares sin base (solo cuadrícula)
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height/2);
      ctx.rotate(obs.tilt);

      // Rectángulo base oscuro
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.rect(-obs.width/2, -obs.height/2, obs.width, obs.height);
      ctx.fill(); ctx.stroke();

      // Cuadrícula técnica (estilo Windmar Home)
      ctx.strokeStyle = 'rgba(59, 130, 246, 0.5)';
      ctx.lineWidth = 1;
      for(let i = 1; i < 3; i++) {
        const lx = -obs.width/2 + (obs.width / 3) * i;
        ctx.beginPath(); ctx.moveTo(lx, -obs.height/2); ctx.lineTo(lx, obs.height/2); ctx.stroke();
      }
      for(let i = 1; i < 4; i++) {
        const ly = -obs.height/2 + (obs.height / 4) * i;
        ctx.beginPath(); ctx.moveTo(-obs.width/2, ly); ctx.lineTo(obs.width/2, ly); ctx.stroke();
      }

      ctx.restore();
    });

    // 4. Jhonny
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (invulnerableTimer.current > 0 && Math.floor(Date.now() / 50) % 2 === 0) {
      ctx.globalAlpha = 0.3;
    }

    // Aura de NITRO si tiene boost
    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 30; ctx.shadowColor = '#60a5fa';
      // Partículas extra de velocidad detrás
      for(let i=0; i<2; i++) {
        particles.current.push({
          x: pX - 40, y: pY + 20,
          vx: -15, vy: (Math.random() - 0.5) * 5,
          life: 0.2, size: 2, color: '#60a5fa'
        });
      }
    }

    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);
    ctx.globalAlpha = 1.0;

    // Logo de Windmar Home como Power Up Flotante
    if (player.current.boostRemaining > 0) {
      const logoW = 140, logoH = 35;
      const bounceY = Math.sin(Date.now() * 0.01) * 8;
      if (windmarImg.current.complete) {
        ctx.rotate(-player.current.rotation);
        ctx.shadowBlur = 10; ctx.shadowColor = 'white';
        ctx.drawImage(windmarImg.current, -logoW/2, -sH/2 - 50 + bounceY, logoW, logoH);
      }
    }

    if (player.current.guayandoTimer > 0 && player.current.boostRemaining <= 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 100, bH = 30;
      ctx.beginPath(); ctx.roundRect(40, -sH/2 - 25, bW, bH, 8); ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8'; ctx.font = 'bold 12px Arial'; ctx.textAlign = 'center';
      ctx.fillText("¡PRÓXIMA PARADA!", 40 + bW/2, -sH/2 - 6);
    }
    ctx.restore();

    // 5. Quejas de Apagón
    if (complaintRef.current) {
      ctx.save();
      const alpha = Math.min(1, complaintRef.current.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(260, width * 0.4);
      const cH = 50;
      ctx.fillStyle = '#fee2e2'; ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(width - cW - 40, 40, cW, cH, 12); ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#991b1b'; ctx.font = 'italic 14px Permanent Marker'; ctx.textAlign = 'center';
      ctx.fillText(complaintRef.current.text, width - cW/2 - 40, 40 + cH/2 + 5);
      ctx.restore();
    }

    // 6. Soles distribuidos
    collectibles.current.forEach(sun => {
      ctx.fillStyle = '#fde047';
      ctx.beginPath(); ctx.arc(sun.x + 18, sun.y + 18, 14, 0, Math.PI*2); ctx.fill();
      ctx.strokeStyle = '#ea580c'; ctx.stroke();
      ctx.fillStyle = 'white';
      ctx.beginPath(); ctx.arc(sun.x + 12, sun.y + 12, 4, 0, Math.PI*2); ctx.fill();
    });

    // 7. UI Superior Izquierda
    ctx.fillStyle = 'rgba(15, 23, 42, 0.85)';
    ctx.beginPath(); ctx.roundRect(20, 20, 220, 95, 12); ctx.fill();
    ctx.strokeStyle = '#3b82f6'; ctx.lineWidth = 2; ctx.stroke();

    ctx.fillStyle = 'white';
    ctx.font = '16px Bangers'; ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 35, 42);
    ctx.font = '12px Bangers';
    ctx.fillText(`PROGRESO: ${Math.floor(distance.current)}m`, 35, 60);

    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 35 + (i*20), 80);
    }

    // Barra de Progreso a la Meta
    const totalDistance = METERS_PER_CITY * CITIES.length;
    const progress = Math.min(1, distance.current / totalDistance);
    const barW = 180, barH = 6;
    ctx.fillStyle = '#334155';
    ctx.fillRect(35, 95, barW, barH);
    ctx.fillStyle = '#3b82f6';
    ctx.fillRect(35, 95, barW * progress, barH);

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    requestRef.current = requestAnimationFrame(update);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [update]);

  return (
    <div ref={containerRef} className="w-full h-full relative">
      <canvas ref={canvasRef} className="w-full h-full block cursor-pointer" />
    </div>
  );
};

export default Game;

