        player.current.squashX = 1.25; 
        player.current.squashY = 0.75;
        player.current.landingTimer = 6;
        createExplosion(player.current.x + 40, actualFootY, '#dddddd');
      }

      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;

      if (player.current.landingTimer > 0) {
        player.current.landingTimer--;
      } else {
        player.current.squashX += (1 - player.current.squashX) * 0.2;
        player.current.squashY += (1 - player.current.squashY) * 0.2;
      }

      player.current.vibrationY = Math.sin(Date.now() * 0.12) * 1.2;
      player.current.rotation = Math.sin(Date.now() * 0.06) * 0.01;

      if (Math.random() > 0.8) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -4 - Math.random() * 4, vy: -1 - Math.random() * 1.5,
          life: 0.3, size: 1.5, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) {
      player.current.boostRemaining -= currentSpeed;
    }
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;
    if (invulnerableTimer.current > 0) invulnerableTimer.current--;

    // Colisiones Obstáculos
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;
      const pX = player.current.x + 30;
      const pY = player.current.y + 30;
      const pW = player.current.width - 60;
      const pH = player.current.height - 35;

      if (gameActive.current && invulnerableTimer.current === 0 &&
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < obs.y + obs.height && pY + pH > obs.y) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + 35, obs.y + 45, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invulnerableTimer.current = 60;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          complaintRef.current = {text: phrase, timer: 120};
          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');

          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -200) obstacles.current.splice(index, 1);
    });

    // Colisiones Colectables
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + item.width && player.current.x + player.current.width > item.x &&
          player.current.y < item.y + item.height && player.current.y + player.current.height > item.y) {

        if (item.type === 'sun') {
          sunsCollected.current++;
          totalScore.current += 100;
        } else {
          // Es Nitro
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 120; // Mostrar "GUAYANDO"
          totalScore.current += 1000;
        }

        collectibles.current.splice(index, 1);
      }
      if (item.x + item.width < -100) collectibles.current.splice(index, 1);
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.025;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaintRef.current) {
      if (complaintRef.current.timer > 0) complaintRef.current.timer--;
      else complaintRef.current = null;
    }

    spawnObstacles(width, height);
    spawnCollectibles(width, height, groundY);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    // 1. Fondo Ciudad
    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
      ctx.fillStyle = 'rgba(0, 0, 0, 0.45)';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Carretera
    ctx.fillStyle = '#064e3b';
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#1e293b';
    ctx.fillRect(0, groundY + 8, width, height - groundY - 8);
    ctx.fillStyle = '#cbd5e1';
    ctx.fillRect(0, groundY + 10, width, 3);
    ctx.fillRect(0, height - 10, width, 3);
    ctx.strokeStyle = '#fde047';
    ctx.lineWidth = 4;
    ctx.setLineDash([40, 60]);
    ctx.lineDashOffset = (distance.current * 30) % 100;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 2); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 2);
    ctx.stroke();
    ctx.setLineDash([]);

    // 3. Obstáculos
    obstacles.current.forEach(obs => {
      ctx.save();
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height/2);
      ctx.rotate(obs.tilt);
      ctx.fillStyle = '#0f172a';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.rect(-obs.width/2, -obs.height/2, obs.width, obs.height);
      ctx.fill(); ctx.stroke();
      ctx.strokeStyle = 'rgba(59, 130, 246, 0.5)';
      ctx.lineWidth = 1;
      for(let i = 1; i < 3; i++) {
        const lx = -obs.width/2 + (obs.width / 3) * i;
        ctx.beginPath(); ctx.moveTo(lx, -obs.height/2); ctx.lineTo(lx, obs.height/2); ctx.stroke();
      }
      for(let i = 1; i < 4; i++) {
        const ly = -obs.height/2 + (obs.height / 4) * i;
        ctx.beginPath(); ctx.moveTo(-obs.width/2, ly); ctx.lineTo(obs.width/2, ly); ctx.stroke();
      }
      ctx.restore();
    });

    // 4. Jhonny
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (invulnerableTimer.current > 0 && Math.floor(Date.now() / 50) % 2 === 0) {
      ctx.globalAlpha = 0.3;
    }

    if (player.current.boostRemaining > 0) {
      ctx.shadowBlur = 30; ctx.shadowColor = '#60a5fa';
    }

    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);
    ctx.globalAlpha = 1.0;

    // Logo de Windmar Home arriba cuando hay Nitro
    if (player.current.boostRemaining > 0) {
      const logoW = 120, logoH = 30;
      const bounceY = Math.sin(Date.now() * 0.01) * 6;
      if (windmarImg.current.complete) {
        ctx.rotate(-player.current.rotation);
        ctx.shadowBlur = 10; ctx.shadowColor = 'white';
        ctx.drawImage(windmarImg.current, -logoW/2, -sH/2 - 55 + bounceY, logoW, logoH);
      }
    }

    // Mensaje "GUAYANDO"
    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white';
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      const bW = 120, bH = 35;
      ctx.beginPath(); ctx.roundRect(-bW/2 + 60, -sH/2 - 25, bW, bH, 8); ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8'; 
      ctx.font = 'bold 16px Bangers'; 
      ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 60, -sH/2 - 2);
    }
    ctx.restore();

    // 5. Quejas
    if (complaintRef.current) {
      ctx.save();
      const alpha = Math.min(1, complaintRef.current.timer / 20);
      ctx.globalAlpha = alpha;
      const cW = Math.min(260, width * 0.4);
      const cH = 50;
      ctx.fillStyle = '#fee2e2'; ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(width - cW - 40, 40, cW, cH, 12); ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#991b1b'; ctx.font = 'italic 14px Permanent Marker'; ctx.textAlign = 'center';
      ctx.fillText(complaintRef.current.text, width - cW/2 - 40, 40 + cH/2 + 5);
      ctx.restore();
    }

    // 6. Coleccionables (Soles y Logos Windmar)
    collectibles.current.forEach(item => {
      if (item.type === 'sun') {
        ctx.fillStyle = '#fde047';
        ctx.beginPath(); ctx.arc(item.x + 18, item.y + 18, 14, 0, Math.PI*2); ctx.fill();
        ctx.strokeStyle = '#ea580c'; ctx.stroke();
        ctx.fillStyle = 'white';
        ctx.beginPath(); ctx.arc(item.x + 12, item.y + 12, 4, 0, Math.PI*2); ctx.fill();
      } else {
        // Logo Windmar (Nitro)
        if (windmarImg.current.complete) {
          ctx.save();
          ctx.shadowBlur = 15; ctx.shadowColor = '#3b82f6';
          // Dibujar un pequeño aura azul detrás del logo
          ctx.fillStyle = 'rgba(59, 130, 246, 0.3)';
          ctx.beginPath();
          ctx.roundRect(item.x - 5, item.y - 5, item.width + 10, item.height + 10, 5);
          ctx.fill();
          ctx.drawImage(windmarImg.current, item.x, item.y, item.width, item.height);
          ctx.restore();
        }
      }
    });

    // 7. UI Superior Izquierda
    ctx.fillStyle = 'rgba(15, 23, 42, 0.85)';
    ctx.beginPath(); ctx.roundRect(20, 20, 220, 95, 12); ctx.fill();
    ctx.strokeStyle = '#3b82f6'; ctx.lineWidth = 2; ctx.stroke();

    ctx.fillStyle = 'white';
    ctx.font = '16px Bangers'; ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, 35, 42);
    ctx.font = '12px Bangers';
    ctx.fillText(`PUNTOS: ${totalScore.current}`, 35, 60);

    for(let i=0; i<MAX_LIVES; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", 35 + (i*20), 80);
    }

    const totalDistance = METERS_PER_CITY * CITIES.length;
    const progress = Math.min(1, distance.current / totalDistance);
    const barW = 180, barH = 6;
    ctx.fillStyle = '#334155';
    ctx.fillRect(35, 95, barW, barH);
    ctx.fillStyle = '#3b82f6';
    ctx.fillRect(35, 95, barW * progress, barH);

    // Partículas
    particles.current.forEach(p => {
      ctx.globalAlpha = p.life;
      ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    requestRef.current = requestAnimationFrame(update);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [update]);

  return (
    <div ref={containerRef} className="w-full h-full relative">
      <canvas ref={canvasRef} className="w-full h-full block cursor-pointer" />
    </div>
  );
};

export default Game;

