            alt="Windmar Logo Right" 
            className="h-10 sm:h-28 w-auto drop-shadow-[0_0_25px_rgba(59,130,246,0.8)]" 
          />
        </div>
      </header>

      {/* MARCO DEL JUEGO CON BORDES GLOW */}
