import React, { useEffect, useRef, useState, useCallback } from 'react';
import { 
  GRAVITY, 
  JUMP_FORCE, 
  DOUBLE_JUMP_FORCE,
  BASE_SPEED, 
  SPEED_INCREMENT, 
  METERS_PER_CITY, 
  TREX_IMAGE_URL,
  FLOATING_OBSTACLE_URL,
  POWERUP_BOOST_DISTANCE,
  BACKGROUND_URLS,
  MAX_LIVES_INITIAL,
  MAX_LIVES_LIMIT,
  SUNS_PER_LIFE,
  ERROR_PHRASES
} from '../constants';
import { CITIES } from '../types';

interface GameProps {
  onGameOver: (score: number, distance: number, city: string, win?: boolean) => void;
}

interface Particle {
  x: number; y: number; vx: number; vy: number; life: number; size: number; color: string;
}

interface Collectible {
  x: number;
  y: number;
  width: number;
  height: number;
  type: 'sun' | 'nitro';
}

interface Obstacle {
  x: number;
  y: number;
  width: number;
  height: number;
  tilt: number;
  type: 'ground' | 'floating';
  bobOffset?: number;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>(0);

  const gameActive = useRef(true);
  const distance = useRef(0);
  const sunsCollected = useRef(0);
  const totalScore = useRef(0);
  const currentCityIndex = useRef(0);
  const lives = useRef(MAX_LIVES_INITIAL);
  const obstacleCooldown = useRef(0);
  const collectibleCooldown = useRef(0);
  const invulnerableTimer = useRef(0);

  const complaintRef = useRef<{text: string, timer: number} | null>(null);

  const player = useRef({
    x: 150,
    y: 0,
    width: 90,
    height: 90,
    dy: 0,
    rotation: 0,
    jumpCount: 0,
    boostRemaining: 0,
    guayandoTimer: 0,
    isJumping: false,
    vibrationY: 0,
    squashX: 1,
    squashY: 1,
    landingTimer: 0
  });

  const obstacles = useRef<Obstacle[]>([]);
  const collectibles = useRef<Collectible[]>([]);
  const particles = useRef<Particle[]>([]);
  const trexImg = useRef<HTMLImageElement>(new Image());
  const floatingImg = useRef<HTMLImageElement>(new Image());
  const backgroundImages = useRef<HTMLImageElement[]>([]);

  const handleJump = useCallback(() => {
    if (!gameActive.current) return;
    if (player.current.jumpCount < 2) {
      player.current.dy = player.current.jumpCount === 0 ? JUMP_FORCE : DOUBLE_JUMP_FORCE;
      player.current.jumpCount++;
      player.current.isJumping = true;
      player.current.squashX = 0.8;
      player.current.squashY = 1.2;
      createExplosion(player.current.x + 30, player.current.y + 80, '#ffffff');
    }
  }, []);

  useEffect(() => {
    trexImg.current.src = TREX_IMAGE_URL;
    floatingImg.current.src = FLOATING_OBSTACLE_URL;
    BACKGROUND_URLS.forEach((url, i) => {
      const img = new Image();
      img.src = url;
      backgroundImages.current[i] = img;
    });

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.code === 'Space' || e.code === 'ArrowUp') {
        e.preventDefault();
        handleJump();
      }
    };

    const handleTouchStart = (e: TouchEvent) => {
      // Prevent scrolling while playing
      if (gameActive.current) {
        e.preventDefault();
        handleJump();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('touchstart', handleTouchStart, { passive: false });

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('touchstart', handleTouchStart);
    };
  }, [handleJump]);

  const createExplosion = (x: number, y: number, color: string) => {
    for(let i=0; i<8; i++) {
      particles.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 8,
        vy: (Math.random() - 0.5) * 8,
        life: 1.0,
        size: 2 + Math.random() * 3,
        color
      });
    }
  };

  const spawnObstacles = (canvasWidth: number, canvasHeight: number) => {
    if (obstacleCooldown.current > 0) {
      obstacleCooldown.current--;
      return;
    }

    if (Math.random() < 0.035) {
      const pattern = Math.random();
      const groundY = canvasHeight - 70;
      const obsY = canvasHeight - 125;
      const baseObsWidth = 85;
      const baseObsHeight = 95;

      if (pattern < 0.2) {
        obstacles.current.push({ 
          x: canvasWidth, 
          y: groundY - 150 - Math.random() * 60, 
          width: 55, 
          height: 65, 
          tilt: 0, 
          type: 'floating',
          bobOffset: Math.random() * Math.PI * 2
        });
        obstacleCooldown.current = 90;
      } else if (pattern < 0.5) {
        obstacles.current.push({ x: canvasWidth, y: obsY, width: baseObsWidth, height: baseObsHeight, tilt: 0, type: 'ground' });
        obstacles.current.push({ x: canvasWidth, y: obsY - baseObsHeight - 2, width: baseObsWidth, height: baseObsHeight, tilt: 0, type: 'ground' });
        obstacleCooldown.current = 110;
      } else if (pattern < 0.75) {
        obstacles.current.push({ x: canvasWidth, y: obsY, width: baseObsWidth, height: baseObsHeight, tilt: 0.04, type: 'ground' });
        obstacles.current.push({ x: canvasWidth + 140, y: obsY, width: baseObsWidth, height: baseObsHeight, tilt: -0.04, type: 'ground' });
        obstacleCooldown.current = 130;
      } else {
        obstacles.current.push({ x: canvasWidth, y: obsY, width: baseObsWidth, height: baseObsHeight, tilt: 0, type: 'ground' });
        obstacles.current.push({ x: canvasWidth + 220, y: obsY, width: baseObsWidth, height: baseObsHeight, tilt: 0, type: 'ground' });
        obstacles.current.push({ x: canvasWidth + 440, y: obsY, width: baseObsWidth, height: baseObsHeight, tilt: 0, type: 'ground' });
        obstacleCooldown.current = 160;
      }
    }
  };

  const spawnCollectibles = (canvasWidth: number, canvasHeight: number, groundY: number) => {
    if (collectibleCooldown.current > 0) {
      collectibleCooldown.current--;
      return;
    }

    if (Math.random() < 0.025) {
      const isNitro = Math.random() < 0.12;
      collectibles.current.push({ 
        x: canvasWidth, 
        y: groundY - 130 - Math.random() * 140, 
        width: isNitro ? 55 : 35,
        height: isNitro ? 55 : 35,
        type: isNitro ? 'nitro' : 'sun'
      });
      collectibleCooldown.current = 50 + Math.random() * 70;
    }
  }

  const update = useCallback(() => {
    if (!gameActive.current) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;
    const groundY = height - 70; 

    // Adjust speed based on screen size (slower for small screens)
    const responsiveMultiplier = width < 600 ? 0.8 : 1;
    const currentSpeed = (BASE_SPEED + (currentCityIndex.current * SPEED_INCREMENT) + (player.current.boostRemaining > 0 ? 15 : 0)) * responsiveMultiplier;
    distance.current += currentSpeed / 60;

    const nextCityIndex = Math.floor(distance.current / METERS_PER_CITY);

    if (nextCityIndex >= CITIES.length) {
      gameActive.current = false;
      onGameOver(totalScore.current, distance.current, CITIES[CITIES.length-1], true);
      return;
    }

    if (nextCityIndex > currentCityIndex.current) {
      currentCityIndex.current = nextCityIndex;
      player.current.guayandoTimer = 90;
    }

    // Physics
    player.current.y += player.current.dy;
    const actualFootY = groundY + 38; 

    if (player.current.y + player.current.height < actualFootY) {
      player.current.dy += GRAVITY;
      player.current.rotation = player.current.dy * 0.02;
    } else {
      if (player.current.isJumping) {
        player.current.isJumping = false;
        player.current.squashX = 1.25; 
        player.current.squashY = 0.75;
        player.current.landingTimer = 6;
        createExplosion(player.current.x + 40, actualFootY, '#ffffff');
      }
      player.current.y = actualFootY - player.current.height;
      player.current.dy = 0;
      player.current.jumpCount = 0;
      if (player.current.landingTimer > 0) player.current.landingTimer--;
      else {
        player.current.squashX += (1 - player.current.squashX) * 0.2;
        player.current.squashY += (1 - player.current.squashY) * 0.2;
      }
      player.current.vibrationY = Math.sin(Date.now() * 0.12) * 1.5;
      player.current.rotation = Math.sin(Date.now() * 0.06) * 0.01;

      if (Math.random() > 0.8) {
        particles.current.push({
          x: player.current.x + 10, y: actualFootY,
          vx: -4 - Math.random() * 4, vy: -1 - Math.random() * 1.5,
          life: 0.3, size: 1.5, color: '#fcd34d'
        });
      }
    }

    if (player.current.boostRemaining > 0) player.current.boostRemaining -= currentSpeed;
    if (player.current.guayandoTimer > 0) player.current.guayandoTimer--;
    if (invulnerableTimer.current > 0) invulnerableTimer.current--;

    // Collision Obstacles
    obstacles.current.forEach((obs, index) => {
      obs.x -= currentSpeed;

      const pX = player.current.x + 40;
      const pY = player.current.y + 40;
      const pW = player.current.width - 70;
      const pH = player.current.height - 50;

      const bob = obs.type === 'floating' ? Math.sin(Date.now() * 0.005 + (obs.bobOffset || 0)) * 15 : 0;
      const actualObsY = obs.y + bob;

      if (gameActive.current && invulnerableTimer.current === 0 &&
          pX < obs.x + obs.width && pX + pW > obs.x &&
          pY < actualObsY + obs.height && pY + pH > actualObsY) {

        if (player.current.boostRemaining > 0) {
          obstacles.current.splice(index, 1);
          createExplosion(obs.x + obs.width/2, actualObsY + obs.height/2, '#60a5fa');
          totalScore.current += 500;
        } else {
          lives.current -= 1;
          invulnerableTimer.current = 60;
          const phrase = ERROR_PHRASES[Math.floor(Math.random() * ERROR_PHRASES.length)];
          complaintRef.current = {text: phrase, timer: 120};
          obstacles.current.splice(index, 1);
          createExplosion(pX, pY, '#ef4444');
          if (lives.current <= 0) {
            gameActive.current = false;
            onGameOver(totalScore.current, distance.current, CITIES[currentCityIndex.current]);
          }
        }
      }
      if (obs.x + obs.width < -500) obstacles.current.splice(index, 1);
    });

    // Collision Collectibles
    collectibles.current.forEach((item, index) => {
      item.x -= currentSpeed;
      if (player.current.x < item.x + item.width && player.current.x + player.current.width > item.x &&
          player.current.y < item.y + item.height && player.current.y + player.current.height > item.y) {

        if (item.type === 'sun') {
          sunsCollected.current++;
          totalScore.current += 100;
          if (sunsCollected.current % SUNS_PER_LIFE === 0) {
            if (lives.current < MAX_LIVES_LIMIT) {
              lives.current++;
              createExplosion(player.current.x + 50, player.current.y + 20, '#ef4444');
            }
          }
        } else {
          player.current.boostRemaining += POWERUP_BOOST_DISTANCE;
          player.current.guayandoTimer = 120;
          totalScore.current += 1000;
        }
        collectibles.current.splice(index, 1);
      }
      if (item.x + item.width < -100) collectibles.current.splice(index, 1);
    });

    particles.current.forEach((p, i) => {
      p.x += p.vx; p.y += p.vy; p.life -= 0.025;
      if (p.life <= 0) particles.current.splice(i, 1);
    });

    if (complaintRef.current) {
      if (complaintRef.current.timer > 0) complaintRef.current.timer--;
      else complaintRef.current = null;
    }

    spawnObstacles(width, height);
    spawnCollectibles(width, height, groundY);
    draw(ctx, width, height, groundY);
    requestRef.current = requestAnimationFrame(update);
  }, [onGameOver, handleJump]);

  const draw = (ctx: CanvasRenderingContext2D, width: number, height: number, groundY: number) => {
    ctx.clearRect(0, 0, width, height);

    const bgImg = backgroundImages.current[currentCityIndex.current];
    if (bgImg?.complete) {
      ctx.drawImage(bgImg, 0, 0, width, height);
    } else {
      ctx.fillStyle = '#1e293b';
      ctx.fillRect(0, 0, width, height);
    }

    // 2. Road
    ctx.fillStyle = '#064e3b'; 
    ctx.fillRect(0, groundY, width, height - groundY);
    ctx.fillStyle = '#0f172a'; 
    ctx.fillRect(0, groundY + 10, width, height - groundY - 10);

    ctx.fillStyle = '#64748b';
    ctx.fillRect(0, groundY + 12, width, 2);
    ctx.fillRect(0, height - 12, width, 2);

    ctx.strokeStyle = '#fbbf24';
    ctx.lineWidth = 5;
    ctx.setLineDash([60, 80]);
    ctx.lineDashOffset = (distance.current * 40) % 140;
    ctx.beginPath();
    ctx.moveTo(0, groundY + (height - groundY)/2 + 5); 
    ctx.lineTo(width, groundY + (height - groundY)/2 + 5);
    ctx.stroke();
    ctx.setLineDash([]);

    if (player.current.boostRemaining > 0) {
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
      ctx.lineWidth = 3;
      for(let i=0; i<20; i++) {
        const lx = Math.random() * width;
        const ly = Math.random() * height;
        const len = 100 + Math.random() * 150;
        ctx.beginPath();
        ctx.moveTo(lx, ly);
        ctx.lineTo(lx - len, ly);
        ctx.stroke();
      }
    }

    // 4. Obstacles
    obstacles.current.forEach(obs => {
      ctx.save();
      const bob = obs.type === 'floating' ? Math.sin(Date.now() * 0.005 + (obs.bobOffset || 0)) * 15 : 0;
      ctx.translate(obs.x + obs.width/2, obs.y + obs.height/2 + bob);
      ctx.rotate(obs.tilt);

      if (obs.type === 'ground') {
        ctx.fillStyle = '#334155';
        ctx.shadowBlur = 12; ctx.shadowColor = 'rgba(0,0,0,0.7)';
        ctx.beginPath(); ctx.roundRect(-obs.width/2, -obs.height/2, obs.width, obs.height, 6); ctx.fill();
        ctx.shadowBlur = 0;

        const cols = 4; const rows = 4;
        const cellW = (obs.width - 8) / cols;
        const cellH = (obs.height - 8) / rows;
        for(let c=0; c<cols; c++) {
          for(let r=0; r<rows; r++) {
            ctx.fillStyle = '#0f172a';
            ctx.fillRect(-obs.width/2+4+c*cellW+1, -obs.height/2+4+r*cellH+1, cellW-2, cellH-2);
            ctx.fillStyle = 'rgba(59, 130, 246, 0.2)';
            ctx.fillRect(-obs.width/2+4+c*cellW+2, -obs.height/2+4+r*cellH+2, cellW/2, cellH/3);
          }
        }
        const gradient = ctx.createLinearGradient(-obs.width/2, -obs.height/2, obs.width/2, obs.height/2);
        gradient.addColorStop(0, 'rgba(255,255,255,0)');
        gradient.addColorStop(0.5, 'rgba(255,255,255,0.15)');
        gradient.addColorStop(1, 'rgba(255,255,255,0)');
        ctx.fillStyle = gradient;
        ctx.fillRect(-obs.width/2, -obs.height/2, obs.width, obs.height);

      } else {
        if (floatingImg.current.complete) {
          ctx.drawImage(floatingImg.current, -obs.width/2, -obs.height/2, obs.width, obs.height);
          ctx.strokeStyle = 'rgba(239, 68, 68, 0.6)';
          ctx.lineWidth = 3;
          ctx.beginPath(); ctx.ellipse(0, 0, obs.width/2+8, obs.height/2+8, 0, 0, Math.PI*2); ctx.stroke();
        }
      }
      ctx.restore();
    });

    // 5. Player
    ctx.save();
    const sW = player.current.width * player.current.squashX;
    const sH = player.current.height * player.current.squashY;
    const pX = player.current.x + player.current.width/2;
    const pY = player.current.y + player.current.height/2 + player.current.vibrationY;

    ctx.translate(pX, pY);
    ctx.rotate(player.current.rotation);
    if (invulnerableTimer.current > 0 && Math.floor(Date.now() / 50) % 2 === 0) ctx.globalAlpha = 0.4;
    if (player.current.boostRemaining > 0) { ctx.shadowBlur = 40; ctx.shadowColor = '#60a5fa'; }
    ctx.drawImage(trexImg.current, -sW/2, -sH/2, sW, sH);
    ctx.globalAlpha = 1.0;

    if (player.current.guayandoTimer > 0) {
      ctx.rotate(-player.current.rotation);
      ctx.fillStyle = 'white'; ctx.strokeStyle = '#3b82f6'; ctx.lineWidth = 3;
      const bW = 130, bH = 40;
      ctx.beginPath(); ctx.roundRect(-bW/2 + 65, -sH/2 - 30, bW, bH, 10); ctx.fill(); ctx.stroke();
      ctx.fillStyle = '#1d4ed8'; ctx.font = 'bold 18px Bangers'; ctx.textAlign = 'center';
      ctx.fillText("¡GUAYANDO!", 65, -sH/2 - 3);
    }
    ctx.restore();

    // 6. Collectibles
    collectibles.current.forEach(item => {
      if (item.type === 'sun') {
        ctx.fillStyle = '#fde047';
        ctx.beginPath(); ctx.arc(item.x + 18, item.y + 18, 16, 0, Math.PI*2); ctx.fill();
        ctx.strokeStyle = '#ea580c'; ctx.lineWidth = 2; ctx.stroke();
      } else {
        const bounce = Math.sin(Date.now() * 0.015) * 10;
        ctx.font = '45px serif'; ctx.textAlign = 'center';
        ctx.shadowBlur = 20; ctx.shadowColor = '#fbbf24';
        ctx.fillText("⚡", item.x + item.width/2, item.y + item.height/2 + bounce);
        ctx.shadowBlur = 0;
      }
    });

    // 7. UI
    const isMobile = width < 600;
    const uiX = isMobile ? 10 : 20;
    const uiY = isMobile ? 10 : 20;
    const uiW = isMobile ? 180 : 240;
    const uiH = isMobile ? 80 : 100;

    ctx.fillStyle = 'rgba(15, 23, 42, 0.9)';
    ctx.beginPath(); ctx.roundRect(uiX, uiY, uiW, uiH, 15); ctx.fill();
    ctx.strokeStyle = '#3b82f6'; ctx.lineWidth = 2; ctx.stroke();

    ctx.fillStyle = 'white';
    ctx.font = isMobile ? '14px Bangers' : '18px Bangers'; ctx.textAlign = 'left';
    ctx.fillText(`${CITIES[currentCityIndex.current]}`, uiX + 15, uiY + 25);
    ctx.font = isMobile ? '12px Bangers' : '14px Bangers';
    ctx.fillText(`PUNTOS: ${totalScore.current}   ☀️: ${sunsCollected.current}`, uiX + 15, uiY + 45);
    for(let i=0; i<MAX_LIVES_LIMIT; i++) {
      ctx.fillText(i < lives.current ? "❤️" : "🖤", uiX + 15 + (i * (isMobile ? 18 : 22)), uiY + 65);
    }
    const totalDistance = METERS_PER_CITY * CITIES.length;
    const progress = Math.min(1, distance.current / totalDistance);
    ctx.fillStyle = '#334155'; ctx.fillRect(uiX + 15, uiY + 75, uiW - 30, 6);
    ctx.fillStyle = '#3b82f6'; ctx.fillRect(uiX + 15, uiY + 75, (uiW - 30) * progress, 6);

    particles.current.forEach(p => {
      ctx.globalAlpha = p.life; ctx.fillStyle = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha = 1.0;
  };

  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current && canvasRef.current.parentElement) {
        canvasRef.current.width = canvasRef.current.parentElement.clientWidth;
        canvasRef.current.height = canvasRef.current.parentElement.clientHeight;
      }
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    requestRef.current = requestAnimationFrame(update);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [update]);

  return (
    <div ref={containerRef} className="w-full h-full relative overflow-hidden">
      <canvas ref={canvasRef} className="w-full h-full block cursor-pointer" />
      {/* Visual touch feedback hint for mobile */}
      <div className="absolute bottom-4 right-4 text-white/20 font-cartoon text-sm pointer-events-none md:hidden">
        TAP PARA SALTAR
      </div>
    </div>
  );
};

export default Game;

